diffs.replacement:
{
  "name": "X5 Friends Ranking & Stats",
  "description": "Uma plataforma completa para gerenciar e visualizar estatísticas de jogadores em partidas X5, com suporte a múltiplas temporadas, rankings dinâmicos e análises geradas por IA."
}

export interface Player {
  id: string;
  nick: string;
}

export interface Season {
  id: string;
  name: string;
}

export interface PlayerStats {
  id: string;
  playerId: string;
  seasonId: string;
  matches: number;
  kills: number;
  deaths: number;
  assists: number;
  damage: number;
}

export interface FullRankingEntry extends PlayerStats {
  nick: string;
  kd: number;
  damagePerMatch: number;
}

export type ViewType = 'ranking' | 'admin';

import { Player, Season, PlayerStats } from './types';

export const INITIAL_PLAYERS: Player[] = [
  { id: 'p1', nick: 'Ghost' },
  { id: 'p2', nick: 'Shadow' },
  { id: 'p3', nick: 'Viper' },
  { id: 'p4', nick: 'Blaze' },
  { id: 'p5', nick: 'Cypher' }
];

export const INITIAL_SEASONS: Season[] = [
  { id: 's1', name: 'Temporada 1 - Verão 2024' },
  { id: 's2', name: 'Temporada 2 - Outono 2024' }
];

export const INITIAL_STATS: PlayerStats[] = [
  { id: 'st1', playerId: 'p1', seasonId: 's1', matches: 10, kills: 150, deaths: 80, assists: 45, damage: 25000 },
  { id: 'st2', playerId: 'p2', seasonId: 's1', matches: 10, kills: 120, deaths: 100, assists: 60, damage: 22000 },
  { id: 'st3', playerId: 'p3', seasonId: 's1', matches: 10, kills: 90, deaths: 110, assists: 80, damage: 18000 },
  { id: 'st4', playerId: 'p4', seasonId: 's1', matches: 10, kills: 140, deaths: 95, assists: 30, damage: 23500 },
  { id: 'st5', playerId: 'p5', seasonId: 's1', matches: 10, kills: 110, deaths: 105, assists: 55, damage: 21000 }
];

import { GoogleGenAI } from "@google/genai";
import { FullRankingEntry } from "../types";

export const getRankingInsights = async (ranking: FullRankingEntry[], seasonName: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const rankingSummary = ranking.map(r => 
    `${r.nick}: KD ${r.kd.toFixed(2)}, Dano ${r.damage}, Assistências ${r.assists}`
  ).join('\n');

  const prompt = `
    Como um analista profissional de e-sports, faça uma breve análise (em português) do ranking da ${seasonName}.
    Destaque quem foi o MVP (baseado em KD e Dano) e dê um "conselho" engraçado para quem está na lanterna.
    Seja breve (máximo 150 palavras).

    Dados do Ranking:
    ${rankingSummary}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.8,
      }
    });
    return response.text || "Não foi possível gerar análise no momento.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "O analista de IA está de folga hoje.";
  }
};

import React from 'react';
import { FullRankingEntry } from '../types';

interface RankingTableProps {
  data: FullRankingEntry[];
}

const RankingTable: React.FC<RankingTableProps> = ({ data }) => {
  return (
    <div className="overflow-x-auto rounded-xl border border-slate-700 bg-slate-800/50 backdrop-blur-sm shadow-2xl">
      <table className="w-full text-left border-collapse">
        <thead className="bg-slate-900/80 text-slate-300 font-gaming uppercase tracking-wider text-sm">
          <tr>
            <th className="px-6 py-4">#</th>
            <th className="px-6 py-4">Nick</th>
            <th className="px-6 py-4">Partidas</th>
            <th className="px-6 py-4 text-emerald-400">Vítimas</th>
            <th className="px-6 py-4 text-rose-400">Mortes</th>
            <th className="px-6 py-4 text-sky-400">Assists</th>
            <th className="px-6 py-4 text-orange-400">Dano</th>
            <th className="px-6 py-4 text-yellow-400">K/D</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-700">
          {data.length === 0 ? (
            <tr>
              <td colSpan={8} className="px-6 py-10 text-center text-slate-500 italic">
                Nenhum dado encontrado para esta temporada.
              </td>
            </tr>
          ) : (
            data.sort((a, b) => b.kd - a.kd).map((player, index) => (
              <tr 
                key={player.id} 
                className="hover:bg-slate-700/50 transition-colors group cursor-default"
              >
                <td className="px-6 py-4 font-gaming text-lg">
                  <span className={`
                    w-8 h-8 flex items-center justify-center rounded-full
                    ${index === 0 ? 'bg-yellow-500/20 text-yellow-400 ring-1 ring-yellow-500' : ''}
                    ${index === 1 ? 'bg-slate-400/20 text-slate-300 ring-1 ring-slate-400' : ''}
                    ${index === 2 ? 'bg-orange-700/20 text-orange-400 ring-1 ring-orange-700' : ''}
                  `}>
                    {index + 1}
                  </span>
                </td>
                <td className="px-6 py-4 font-bold text-slate-100 group-hover:text-blue-400 transition-colors">
                  {player.nick}
                </td>
                <td className="px-6 py-4 text-slate-300">{player.matches}</td>
                <td className="px-6 py-4 text-emerald-400 font-medium">{player.kills}</td>
                <td className="px-6 py-4 text-rose-400 font-medium">{player.deaths}</td>
                <td className="px-6 py-4 text-sky-400">{player.assists}</td>
                <td className="px-6 py-4 text-orange-400 font-medium">
                  {player.damage.toLocaleString('pt-BR')}
                </td>
                <td className="px-6 py-4">
                  <span className={`
                    px-2 py-1 rounded font-bold
                    ${player.kd >= 1.5 ? 'bg-emerald-500/20 text-emerald-400' : 
                      player.kd >= 1.0 ? 'bg-blue-500/20 text-blue-400' : 
                      'bg-rose-500/20 text-rose-400'}
                  `}>
                    {player.kd.toFixed(2)}
                  </span>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
};

export default RankingTable;

import React, { useState } from 'react';
import { Player, Season, PlayerStats } from '../types';

interface AdminPanelProps {
  players: Player[];
  seasons: Season[];
  stats: PlayerStats[];
  onAddPlayer: (nick: string) => void;
  onAddSeason: (name: string) => void;
  onUpdateStats: (entry: Omit<PlayerStats, 'id'>) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  players, 
  seasons, 
  stats, 
  onAddPlayer, 
  onAddSeason, 
  onUpdateStats 
}) => {
  const [newPlayerNick, setNewPlayerNick] = useState('');
  const [newSeasonName, setNewSeasonName] = useState('');

  const [selectedPlayerId, setSelectedPlayerId] = useState('');
  const [selectedSeasonId, setSelectedSeasonId] = useState('');
  const [matchData, setMatchData] = useState({
    matches: 0,
    kills: 0,
    deaths: 0,
    assists: 0,
    damage: 0
  });

  const handleUpdateStats = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPlayerId || !selectedSeasonId) return;
    onUpdateStats({
      playerId: selectedPlayerId,
      seasonId: selectedSeasonId,
      ...matchData
    });
    alert('Estatísticas atualizadas com sucesso!');
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
      {/* Cadastro de Jogadores e Temporadas */}
      <div className="space-y-8">
        <section className="bg-slate-800 p-6 rounded-xl border border-slate-700">
          <h3 className="text-xl font-gaming font-bold mb-4 flex items-center gap-2">
            <span className="w-2 h-6 bg-blue-500 rounded-full"></span>
            Novo Jogador
          </h3>
          <div className="flex gap-2">
            <input 
              type="text" 
              value={newPlayerNick}
              onChange={(e) => setNewPlayerNick(e.target.value)}
              placeholder="Nick do jogador..."
              className="flex-1 bg-slate-900 border border-slate-700 rounded px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
            />
            <button 
              onClick={() => { onAddPlayer(newPlayerNick); setNewPlayerNick(''); }}
              className="bg-blue-600 hover:bg-blue-700 px-4 py-2 rounded font-bold transition-colors"
            >
              Adicionar
            </button>
          </div>
        </section>

        <section className="bg-slate-800 p-6 rounded-xl border border-slate-700">
          <h3 className="text-xl font-gaming font-bold mb-4 flex items-center gap-2">
            <span className="w-2 h-6 bg-purple-500 rounded-full"></span>
            Nova Temporada
          </h3>
          <div className="flex gap-2">
            <input 
              type="text" 
              value={newSeasonName}
              onChange={(e) => setNewSeasonName(e.target.value)}
              placeholder="Nome da temporada..."
              className="flex-1 bg-slate-900 border border-slate-700 rounded px-4 py-2 focus:ring-2 focus:ring-purple-500 outline-none"
            />
            <button 
              onClick={() => { onAddSeason(newSeasonName); setNewSeasonName(''); }}
              className="bg-purple-600 hover:bg-purple-700 px-4 py-2 rounded font-bold transition-colors"
            >
              Criar
            </button>
          </div>
        </section>
      </div>

      {/* Vínculo de Estatísticas */}
      <section className="bg-slate-800 p-6 rounded-xl border border-slate-700">
        <h3 className="text-xl font-gaming font-bold mb-4 flex items-center gap-2">
          <span className="w-2 h-6 bg-yellow-500 rounded-full"></span>
          Registrar/Atualizar Stats
        </h3>
        <form onSubmit={handleUpdateStats} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm text-slate-400 mb-1">Jogador</label>
              <select 
                value={selectedPlayerId}
                onChange={(e) => setSelectedPlayerId(e.target.value)}
                className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none"
                required
              >
                <option value="">Selecione...</option>
                {players.map(p => <option key={p.id} value={p.id}>{p.nick}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm text-slate-400 mb-1">Temporada</label>
              <select 
                value={selectedSeasonId}
                onChange={(e) => setSelectedSeasonId(e.target.value)}
                className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none"
                required
              >
                <option value="">Selecione...</option>
                {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm text-slate-400 mb-1">Partidas</label>
              <input 
                type="number" 
                value={matchData.matches}
                onChange={(e) => setMatchData({...matchData, matches: parseInt(e.target.value) || 0})}
                className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm text-slate-400 mb-1">Dano Total</label>
              <input 
                type="number" 
                value={matchData.damage}
                onChange={(e) => setMatchData({...matchData, damage: parseInt(e.target.value) || 0})}
                className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none"
              />
            </div>
          </div>

          <div className="grid grid-cols-3 gap-4">
            <div>
              <label className="block text-sm text-slate-400 mb-1 text-emerald-400">Kills</label>
              <input 
                type="number" 
                value={matchData.kills}
                onChange={(e) => setMatchData({...matchData, kills: parseInt(e.target.value) || 0})}
                className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm text-slate-400 mb-1 text-rose-400">Deaths</label>
              <input 
                type="number" 
                value={matchData.deaths}
                onChange={(e) => setMatchData({...matchData, deaths: parseInt(e.target.value) || 0})}
                className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm text-slate-400 mb-1 text-sky-400">Assists</label>
              <input 
                type="number" 
                value={matchData.assists}
                onChange={(e) => setMatchData({...matchData, assists: parseInt(e.target.value) || 0})}
                className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none"
              />
            </div>
          </div>

          <button 
            type="submit"
            className="w-full bg-emerald-600 hover:bg-emerald-700 py-3 rounded-lg font-bold text-lg transition-all transform hover:scale-[1.02] active:scale-95 shadow-lg shadow-emerald-500/20"
          >
            Salvar Estatísticas
          </button>
        </form>
      </section>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { ViewType, Player, Season, PlayerStats, FullRankingEntry } from './types';
import { INITIAL_PLAYERS, INITIAL_SEASONS, INITIAL_STATS } from './constants';
import RankingTable from './components/RankingTable';
import AdminPanel from './components/AdminPanel';
import { getRankingInsights } from './services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('ranking');
  const [players, setPlayers] = useState<Player[]>(() => {
    const saved = localStorage.getItem('x5_players');
    return saved ? JSON.parse(saved) : INITIAL_PLAYERS;
  });
  const [seasons, setSeasons] = useState<Season[]>(() => {
    const saved = localStorage.getItem('x5_seasons');
    return saved ? JSON.parse(saved) : INITIAL_SEASONS;
  });
  const [stats, setStats] = useState<PlayerStats[]>(() => {
    const saved = localStorage.getItem('x5_stats');
    return saved ? JSON.parse(saved) : INITIAL_STATS;
  });
  const [selectedSeasonId, setSelectedSeasonId] = useState(INITIAL_SEASONS[0].id);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loadingAi, setLoadingAi] = useState(false);

  // Persistência
  useEffect(() => {
    localStorage.setItem('x5_players', JSON.stringify(players));
    localStorage.setItem('x5_seasons', JSON.stringify(seasons));
    localStorage.setItem('x5_stats', JSON.stringify(stats));
  }, [players, seasons, stats]);

  // Cálculo do Ranking Filtrado
  const currentRanking: FullRankingEntry[] = useMemo(() => {
    return stats
      .filter(s => s.seasonId === selectedSeasonId)
      .map(s => {
        const player = players.find(p => p.id === s.playerId);
        return {
          ...s,
          nick: player?.nick || 'Desconhecido',
          kd: s.deaths === 0 ? s.kills : s.kills / s.deaths,
          damagePerMatch: s.matches === 0 ? 0 : s.damage / s.matches
        };
      })
      .sort((a, b) => b.kd - a.kd);
  }, [stats, selectedSeasonId, players]);

  const handleAddPlayer = (nick: string) => {
    if (!nick) return;
    const newPlayer = { id: `p${Date.now()}`, nick };
    setPlayers([...players, newPlayer]);
  };

  const handleAddSeason = (name: string) => {
    if (!name) return;
    const newSeason = { id: `s${Date.now()}`, name };
    setSeasons([...seasons, newSeason]);
    setSelectedSeasonId(newSeason.id);
  };

  const handleUpdateStats = (entry: Omit<PlayerStats, 'id'>) => {
    const existingIndex = stats.findIndex(
      s => s.playerId === entry.playerId && s.seasonId === entry.seasonId
    );
    if (existingIndex > -1) {
      const newStats = [...stats];
      newStats[existingIndex] = { ...newStats[existingIndex], ...entry };
      setStats(newStats);
    } else {
      setStats([...stats, { ...entry, id: `st${Date.now()}` }]);
    }
  };

  const generateAICommentary = async () => {
    if (currentRanking.length === 0) return;
    setLoadingAi(true);
    const seasonName = seasons.find(s => s.id === selectedSeasonId)?.name || 'Temporada';
    const insight = await getRankingInsights(currentRanking, seasonName);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      {/* Header Fixo */}
      <header className="sticky top-0 z-50 bg-slate-900/90 backdrop-blur-md border-b border-slate-800 px-6 py-4 shadow-xl">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center font-gaming text-2xl font-bold italic">X5</div>
            <h1 className="text-2xl font-gaming font-bold tracking-tight bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">
              FRIENDS RANKING
            </h1>
          </div>

          <nav className="flex bg-slate-800 p-1 rounded-lg border border-slate-700">
            <button 
              onClick={() => setView('ranking')}
              className={`px-6 py-2 rounded-md font-bold transition-all ${view === 'ranking' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
              Ranking
            </button>
            <button 
              onClick={() => setView('admin')}
              className={`px-6 py-2 rounded-md font-bold transition-all ${view === 'admin' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
              Gerenciar
            </button>
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {view === 'ranking' ? (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Filtros e Topo */}
            <div className="flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="w-full md:w-auto">
                <label className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-2 block">Selecionar Temporada</label>
                <select 
                  value={selectedSeasonId}
                  onChange={(e) => { setSelectedSeasonId(e.target.value); setAiInsight(''); }}
                  className="w-full md:w-72 bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-blue-500 shadow-lg"
                >
                  {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>

              <div className="flex gap-4">
                <button 
                  onClick={generateAICommentary}
                  disabled={loadingAi || currentRanking.length === 0}
                  className="flex items-center gap-2 bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 px-6 py-3 rounded-xl font-bold shadow-lg transition-transform active:scale-95 disabled:opacity-50"
                >
                  {loadingAi ? (
                    <span className="flex items-center gap-2">
                      <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      Analisando...
                    </span>
                  ) : (
                    <>✨ Análise por IA</>
                  )}
                </button>
              </div>
            </div>

            {/* Insights IA */}
            {aiInsight && (
              <div className="bg-slate-800/80 border border-purple-500/30 p-6 rounded-2xl relative overflow-hidden shadow-2xl">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <svg className="w-24 h-24" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                </div>
                <h4 className="text-purple-400 font-bold mb-2 flex items-center gap-2">
                  <span className="animate-pulse">✨</span> Comentário do Analista
                </h4>
                <p className="text-slate-300 leading-relaxed italic">{aiInsight}</p>
              </div>
            )}

            {/* Gráfico de KD */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
               <div className="lg:col-span-2 bg-slate-900/50 p-6 rounded-2xl border border-slate-800">
                  <h3 className="text-xl font-gaming font-bold mb-6 flex items-center gap-2">
                    <span className="w-2 h-6 bg-emerald-500 rounded-full"></span>
                    Performance Comparada (K/D)
                  </h3>
                  <div className="h-[300px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={currentRanking}>
                        <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                        <XAxis dataKey="nick" stroke="#94a3b8" />
                        <YAxis stroke="#94a3b8" />
                        <Tooltip 
                          contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px' }}
                          itemStyle={{ color: '#fff' }}
                        />
                        <Bar dataKey="kd" radius={[4, 4, 0, 0]}>
                          {currentRanking.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={entry.kd >= 1.5 ? '#10b981' : entry.kd >= 1.0 ? '#3b82f6' : '#f43f5e'} />
                          ))}
                        </Bar>
                      </BarChart>
                    </ResponsiveContainer>
                  </div>
               </div>

               <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800 flex flex-col justify-center text-center">
                  <div className="mb-4">
                    <p className="text-slate-400 uppercase tracking-widest text-sm mb-1">Total de Kills na Temp</p>
                    <p className="text-5xl font-gaming font-bold text-emerald-400">
                      {currentRanking.reduce((acc, curr) => acc + curr.kills, 0)}
                    </p>
                  </div>
                  <div className="h-px bg-slate-800 my-6"></div>
                  <div>
                    <p className="text-slate-400 uppercase tracking-widest text-sm mb-1">Média de Dano</p>
                    <p className="text-4xl font-gaming font-bold text-orange-400">
                      {(currentRanking.reduce((acc, curr) => acc + curr.damage, 0) / (currentRanking.length || 1)).toLocaleString('pt-BR', { maximumFractionDigits: 0 })}
                    </p>
                  </div>
               </div>
            </div>

            {/* Tabela de Ranking */}
            <RankingTable data={currentRanking} />
          </div>
        ) : (
          <div className="animate-in fade-in slide-in-from-right-4 duration-500">
            <h2 className="text-3xl font-gaming font-bold mb-8">Administração do Painel</h2>
            <AdminPanel 
              players={players} 
              seasons={seasons} 
              stats={stats}
              onAddPlayer={handleAddPlayer}
              onAddSeason={handleAddSeason}
              onUpdateStats={handleUpdateStats}
            />
          </div>
        )}
      </main>

      {/* Footer / Info */}
      <footer className="mt-20 border-t border-slate-800 py-10 text-center text-slate-500 text-sm">
