export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { ViewType, Player, Season, PlayerStats, FullRankingEntry } from './types';
import { INITIAL_PLAYERS, INITIAL_SEASONS, INITIAL_STATS } from './constants';
import RankingTable from './components/RankingTable';
import AdminPanel from './components/AdminPanel';
import { getRankingInsights } from './services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

// Senha mestra para demonstração - em produção isso viria de um backend
const ADMIN_PASSWORD = "x5admin2024";

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('ranking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState<boolean>(() => {
    return sessionStorage.getItem('x5_is_admin') === 'true';
  });
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);

  const [players, setPlayers] = useState<Player[]>(() => {
    const saved = localStorage.getItem('x5_players');
    return saved ? JSON.parse(saved) : INITIAL_PLAYERS;
  });
  const [seasons, setSeasons] = useState<Season[]>(() => {
    const saved = localStorage.getItem('x5_seasons');
    return saved ? JSON.parse(saved) : INITIAL_SEASONS;
  });
  const [stats, setStats] = useState<PlayerStats[]>(() => {
    const saved = localStorage.getItem('x5_stats');
    return saved ? JSON.parse(saved) : INITIAL_STATS;
  });
  const [selectedSeasonId, setSelectedSeasonId] = useState(seasons.length > 0 ? seasons[0].id : '');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loadingAi, setLoadingAi] = useState(false);

  // Persistência
  useEffect(() => {
    localStorage.setItem('x5_players', JSON.stringify(players));
    localStorage.setItem('x5_seasons', JSON.stringify(seasons));
    localStorage.setItem('x5_stats', JSON.stringify(stats));
  }, [players, seasons, stats]);

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === ADMIN_PASSWORD) {
      setIsAdminAuthenticated(true);
      sessionStorage.setItem('x5_is_admin', 'true');
      setLoginError(false);
      setAdminPasswordInput('');
    } else {
      setLoginError(true);
      setAdminPasswordInput('');
    }
  };

  const handleLogout = () => {
    setIsAdminAuthenticated(false);
    sessionStorage.removeItem('x5_is_admin');
    setView('ranking');
  };

  // Cálculo do Ranking Filtrado
  const currentRanking: FullRankingEntry[] = useMemo(() => {
    return stats
      .filter(s => s.seasonId === selectedSeasonId)
      .map(s => {
        const player = players.find(p => p.id === s.playerId);
        const kdValue = s.deaths === 0 ? s.kills : s.kills / s.deaths;
        return {
          ...s,
          nick: player?.nick || 'Desconhecido',
          kd: kdValue,
          damagePerMatch: s.matches === 0 ? 0 : s.damage / s.matches
        };
      })
      .sort((a, b) => b.kd - a.kd);
  }, [stats, selectedSeasonId, players]);

  const handleAddPlayer = (nick: string) => {
    if (!isAdminAuthenticated || !nick) return;
    const newPlayer = { id: `p${Date.now()}`, nick };
    setPlayers([...players, newPlayer]);
  };

  const handleEditPlayer = (id: string, newNick: string) => {
    if (!isAdminAuthenticated || !newNick) return;
    setPlayers(players.map(p => p.id === id ? { ...p, nick: newNick } : p));
  };

  const handleDeletePlayer = (id: string) => {
    if (!isAdminAuthenticated) return;
    setPlayers(players.filter(p => p.id !== id));
    setStats(stats.filter(s => s.playerId !== id));
  };

  const handleAddSeason = (name: string) => {
    if (!isAdminAuthenticated || !name) return;
    const newSeason = { id: `s${Date.now()}`, name };
    setSeasons([...seasons, newSeason]);
    if (!selectedSeasonId) setSelectedSeasonId(newSeason.id);
  };

  const handleEditSeason = (id: string, newName: string) => {
    if (!isAdminAuthenticated || !newName) return;
    setSeasons(seasons.map(s => s.id === id ? { ...s, name: newName } : s));
  };

  const handleDeleteSeason = (id: string) => {
    if (!isAdminAuthenticated) return;
    const updatedSeasons = seasons.filter(s => s.id !== id);
    setSeasons(updatedSeasons);
    setStats(stats.filter(s => s.seasonId !== id));
    if (selectedSeasonId === id) {
      setSelectedSeasonId(updatedSeasons.length > 0 ? updatedSeasons[0].id : '');
    }
  };

  const handleUpdateStats = (entry: Omit<PlayerStats, 'id'>) => {
    if (!isAdminAuthenticated) return;
    const existingIndex = stats.findIndex(
      s => s.playerId === entry.playerId && s.seasonId === entry.seasonId
    );
    if (existingIndex > -1) {
      const newStats = [...stats];
      newStats[existingIndex] = { ...newStats[existingIndex], ...entry };
      setStats(newStats);
    } else {
      setStats([...stats, { ...entry, id: `st${Date.now()}` }]);
    }
  };

  const generateAICommentary = async () => {
    if (currentRanking.length === 0) return;
    setLoadingAi(true);
    const seasonName = seasons.find(s => s.id === selectedSeasonId)?.name || 'Temporada';
    const insight = await getRankingInsights(currentRanking, seasonName);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 bg-slate-900/90 backdrop-blur-md border-b border-slate-800 px-6 py-4 shadow-xl">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center font-gaming text-2xl font-bold italic">X5</div>
            <h1 className="text-2xl font-gaming font-bold tracking-tight bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">
              FRIENDS RANKING
            </h1>
          </div>

          <nav className="flex items-center gap-4 bg-slate-800 p-1 rounded-lg border border-slate-700">
            <button 
              onClick={() => setView('ranking')}
              className={`px-6 py-2 rounded-md font-bold transition-all ${view === 'ranking' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
              Ranking
            </button>
            <button 
              onClick={() => setView('admin')}
              className={`px-6 py-2 rounded-md font-bold transition-all ${view === 'admin' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
              Gerenciar
            </button>
            {isAdminAuthenticated && (
              <button 
                onClick={handleLogout}
                className="px-3 py-2 text-rose-500 hover:bg-rose-500/10 rounded-md transition-colors"
                title="Sair do Modo Admin"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M3 3a1 1 0 00-1 1v12a1 1 0 102 0V4a1 1 0 00-1-1zm10.293 9.293a1 1 0 001.414 1.414l3-3a1 1 0 000-1.414l-3-3a1 1 0 10-1.414 1.414L14.586 9H7a1 1 0 100 2h7.586l-1.293 1.293z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {view === 'ranking' ? (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="w-full md:w-auto">
                <label className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-2 block">Selecionar Temporada</label>
                <select 
                  value={selectedSeasonId}
                  onChange={(e) => { setSelectedSeasonId(e.target.value); setAiInsight(''); }}
                  className="w-full md:w-72 bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-blue-500 shadow-lg"
                >
                  {seasons.length === 0 && <option value="">Nenhuma temporada criada</option>}
                  {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>

              <div className="flex gap-4">
                <button 
                  onClick={generateAICommentary}
                  disabled={loadingAi || currentRanking.length === 0}
                  className="flex items-center gap-2 bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 px-6 py-3 rounded-xl font-bold shadow-lg transition-transform active:scale-95 disabled:opacity-50"
                >
                  {loadingAi ? (
                    <span className="flex items-center gap-2">
                      <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      Analisando...
                    </span>
                  ) : (
                    <>✨ Análise por IA</>
                  )}
                </button>
              </div>
            </div>

            {aiInsight && (
              <div className="bg-slate-800/80 border border-purple-500/30 p-6 rounded-2xl relative overflow-hidden shadow-2xl">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <svg className="w-24 h-24" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                </div>
                <h4 className="text-purple-400 font-bold mb-2 flex items-center gap-2">
                  <span className="animate-pulse">✨</span> Comentário do Analista
                </h4>
                <p className="text-slate-300 leading-relaxed italic">{aiInsight}</p>
              </div>
            )}

            {currentRanking.length > 0 ? (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-slate-900/50 p-6 rounded-2xl border border-slate-800">
                    <h3 className="text-xl font-gaming font-bold mb-6 flex items-center gap-2">
                      <span className="w-2 h-6 bg-emerald-500 rounded-full"></span>
                      Performance Comparada (K/D)
                    </h3>
                    <div className="h-[300px] w-full">
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={currentRanking}>
                          <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                          <XAxis dataKey="nick" stroke="#94a3b8" />
                          <YAxis stroke="#94a3b8" />
                          <Tooltip 
                            contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px' }}
                            itemStyle={{ color: '#fff' }}
                          />
                          <Bar dataKey="kd" radius={[4, 4, 0, 0]}>
                            {currentRanking.map((entry, index) => (
                              <Cell key={`cell-${index}`} fill={entry.kd >= 1.5 ? '#10b981' : entry.kd >= 1.0 ? '#3b82f6' : '#f43f5e'} />
                            ))}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                    </div>
                </div>

                <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800 flex flex-col justify-center text-center">
                    <div className="mb-4">
                      <p className="text-slate-400 uppercase tracking-widest text-sm mb-1">Total de Vítimas na Temp</p>
                      <p className="text-5xl font-gaming font-bold text-emerald-400">
                        {currentRanking.reduce((acc, curr) => acc + curr.kills, 0)}
                      </p>
                    </div>
                    <div className="h-px bg-slate-800 my-6"></div>
                    <div>
                      <p className="text-slate-400 uppercase tracking-widest text-sm mb-1">Média de Dano</p>
                      <p className="text-4xl font-gaming font-bold text-orange-400">
                        {(currentRanking.reduce((acc, curr) => acc + curr.damage, 0) / (currentRanking.length || 1)).toLocaleString('pt-BR', { maximumFractionDigits: 0 })}
                      </p>
                    </div>
                </div>
              </div>
            ) : (
               <div className="text-center py-20 bg-slate-900/30 border border-slate-800 rounded-2xl border-dashed">
                 <p className="text-slate-500 text-lg">Sem dados de ranking para exibir. Comece cadastrando estatísticas no painel de gerenciamento.</p>
               </div>
            )}

            {currentRanking.length > 0 && <RankingTable data={currentRanking} />}
          </div>
        ) : !isAdminAuthenticated ? (
          <div className="max-w-md mx-auto mt-20 p-8 bg-slate-900 border border-slate-800 rounded-2xl shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="w-16 h-16 bg-blue-500/10 rounded-full flex items-center justify-center mx-auto mb-6 text-blue-500">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
              </svg>
            </div>
            <h2 className="text-2xl font-gaming font-bold text-center mb-2">Acesso Restrito</h2>
            <p className="text-slate-400 text-center mb-8">Digite a chave de administrador para gerenciar jogadores e temporadas.</p>

            <form onSubmit={handleAdminLogin} className="space-y-4">
              <div>
                <input 
                  type="password" 
                  value={adminPasswordInput}
                  onChange={(e) => setAdminPasswordInput(e.target.value)}
                  placeholder="Senha Administrativa"
                  className={`w-full bg-slate-800 border ${loginError ? 'border-rose-500 ring-rose-500' : 'border-slate-700'} rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-blue-500 transition-all`}
                  autoFocus
                />
                {loginError && <p className="text-rose-500 text-xs mt-2 font-bold animate-bounce">Chave de acesso incorreta.</p>}
              </div>
              <button 
                type="submit"
                className="w-full bg-blue-600 hover:bg-blue-700 py-3 rounded-xl font-bold shadow-lg shadow-blue-500/20 transition-all active:scale-95"
              >
                Entrar no Painel
              </button>
            </form>
          </div>
        ) : (
          <div className="animate-in fade-in slide-in-from-right-4 duration-500">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-3xl font-gaming font-bold">Administração do Painel</h2>
              <div className="bg-emerald-500/10 text-emerald-400 px-3 py-1 rounded-full text-xs font-bold border border-emerald-500/20 flex items-center gap-1">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
                MODO ADMINISTRADOR ATIVO
              </div>
            </div>
            <AdminPanel 
              players={players} 
              seasons={seasons} 
              stats={stats}
              onAddPlayer={handleAddPlayer}
              onEditPlayer={handleEditPlayer}
              onDeletePlayer={handleDeletePlayer}
              onAddSeason={handleAddSeason}
              onEditSeason={handleEditSeason}
              onDeleteSeason={handleDeleteSeason}
              onUpdateStats={handleUpdateStats}
            />
          </div>
        )}
      </main>

      <footer className="mt-20 border-t border-slate-800 py-10 text-center text-slate-500 text-sm">
        <p>© 2024 X5 dos Amigos - Desenvolvido com Gemini AI</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Player, Season, PlayerStats } from '../types';

interface AdminPanelProps {
  players: Player[];
  seasons: Season[];
  stats: PlayerStats[];
  onAddPlayer: (nick: string) => void;
  onEditPlayer: (id: string, newNick: string) => void;
  onDeletePlayer: (id: string) => void;
  onAddSeason: (name: string) => void;
  onEditSeason: (id: string, newName: string) => void;
  onDeleteSeason: (id: string) => void;
  onUpdateStats: (entry: Omit<PlayerStats, 'id'>) => void;
}

interface ConfirmModalState {
  isOpen: boolean;
  type: 'player' | 'season' | null;
  id: string;
  name: string;
}

interface EditModalState {
  isOpen: boolean;
  type: 'player' | 'season' | null;
  id: string;
  value: string;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  players, 
  seasons, 
  onAddPlayer, 
  onEditPlayer,
  onDeletePlayer,
  onAddSeason, 
  onEditSeason,
  onDeleteSeason,
  onUpdateStats 
}) => {
  const [newPlayerNick, setNewPlayerNick] = useState('');
  const [newSeasonName, setNewSeasonName] = useState('');

  const [selectedPlayerId, setSelectedPlayerId] = useState('');
  const [selectedSeasonId, setSelectedSeasonId] = useState('');
  const [matchData, setMatchData] = useState({
    matches: 0,
    kills: 0,
    deaths: 0,
    assists: 0,
    damage: 0
  });

  // Estados de feedback visual
  const [isSavingStats, setIsSavingStats] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [addPlayerSuccess, setAddPlayerSuccess] = useState(false);
  const [addSeasonSuccess, setAddSeasonSuccess] = useState(false);

  const [confirmModal, setConfirmModal] = useState<ConfirmModalState>({
    isOpen: false,
    type: null,
    id: '',
    name: ''
  });

  const [editModal, setEditModal] = useState<EditModalState>({
    isOpen: false,
    type: null,
    id: '',
    value: ''
  });

  const handleUpdateStats = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPlayerId || !selectedSeasonId) return;

    setIsSavingStats(true);

    // Simula um pequeno delay para feedback de carregamento
    setTimeout(() => {
      onUpdateStats({
        playerId: selectedPlayerId,
        seasonId: selectedSeasonId,
        ...matchData
      });

      setIsSavingStats(false);
      setSaveSuccess(true);

      // Limpa apenas os dados numéricos após salvar
      setMatchData({
        matches: 0,
        kills: 0,
        deaths: 0,
        assists: 0,
        damage: 0
      });

      // Remove mensagem de sucesso após 3 segundos
      setTimeout(() => setSaveSuccess(false), 3000);
    }, 400);
  };

  const handleAddPlayerSubmit = () => {
    if (!newPlayerNick.trim()) return;
    onAddPlayer(newPlayerNick);
    setNewPlayerNick('');
    setAddPlayerSuccess(true);
    setTimeout(() => setAddPlayerSuccess(false), 2000);
  };

  const handleAddSeasonSubmit = () => {
    if (!newSeasonName.trim()) return;
    onAddSeason(newSeasonName);
    setNewSeasonName('');
    setAddSeasonSuccess(true);
    setTimeout(() => setAddSeasonSuccess(false), 2000);
  };

  const openConfirmModal = (type: 'player' | 'season', id: string, name: string) => {
    setConfirmModal({ isOpen: true, type, id, name });
  };

  const closeConfirmModal = () => {
    setConfirmModal({ isOpen: false, type: null, id: '', name: '' });
  };

  const openEditModal = (type: 'player' | 'season', id: string, value: string) => {
    setEditModal({ isOpen: true, type, id, value });
  };

  const closeEditModal = () => {
    setEditModal({ isOpen: false, type: null, id: '', value: '' });
  };

  const executeDelete = () => {
    if (confirmModal.type === 'player') onDeletePlayer(confirmModal.id);
    else if (confirmModal.type === 'season') onDeleteSeason(confirmModal.id);
    closeConfirmModal();
  };

  const executeEdit = () => {
    if (!editModal.value.trim()) return;
    if (editModal.type === 'player') onEditPlayer(editModal.id, editModal.value);
    else if (editModal.type === 'season') onEditSeason(editModal.id, editModal.value);
    closeEditModal();
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 relative pb-10">
      {/* Confirmation Modal Overlay */}
      {confirmModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-800 border border-slate-700 p-8 rounded-2xl shadow-2xl max-w-md w-full transform animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-rose-500/10 rounded-full flex items-center justify-center mx-auto mb-6 text-rose-500">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h4 className="text-xl font-gaming font-bold text-center mb-2 text-slate-100">Confirmar Exclusão</h4>
            <p className="text-slate-400 text-center mb-8">
              Tem certeza que deseja excluir {confirmModal.type === 'player' ? 'o jogador' : 'a temporada'} <strong className="text-slate-100">"{confirmModal.name}"</strong>? 
              Esta ação removerá permanentemente todos os dados vinculados e não pode ser desfeita.
            </p>
            <div className="flex gap-4">
              <button 
                onClick={closeConfirmModal}
                className="flex-1 bg-slate-700 hover:bg-slate-600 px-6 py-3 rounded-xl font-bold transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={executeDelete}
                className="flex-1 bg-rose-600 hover:bg-rose-700 px-6 py-3 rounded-xl font-bold transition-colors shadow-lg shadow-rose-600/20"
              >
                Sim, Excluir
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Edit Modal Overlay */}
      {editModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-slate-800 border border-slate-700 p-8 rounded-2xl shadow-2xl max-w-md w-full transform animate-in zoom-in-95 duration-200">
            <h4 className="text-xl font-gaming font-bold text-center mb-6 text-slate-100">
              Editar {editModal.type === 'player' ? 'Jogador' : 'Temporada'}
            </h4>
            <div className="space-y-4 mb-8">
              <label className="block text-sm font-bold text-slate-500 uppercase tracking-widest">Novo Nome</label>
              <input 
                type="text" 
                value={editModal.value}
                onChange={(e) => setEditModal({...editModal, value: e.target.value})}
                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-blue-500 shadow-lg"
                autoFocus
                onKeyDown={(e) => e.key === 'Enter' && executeEdit()}
              />
            </div>
            <div className="flex gap-4">
              <button 
                onClick={closeEditModal}
                className="flex-1 bg-slate-700 hover:bg-slate-600 px-6 py-3 rounded-xl font-bold transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={executeEdit}
                className="flex-1 bg-blue-600 hover:bg-blue-700 px-6 py-3 rounded-xl font-bold transition-colors shadow-lg shadow-blue-600/20"
              >
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Cadastro e Listas */}
      <div className="space-y-8">
        {/* Gestão de Jogadores */}
        <section className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-lg">
          <h3 className="text-xl font-gaming font-bold mb-4 flex items-center gap-2 text-slate-100">
            <span className="w-2 h-6 bg-blue-500 rounded-full"></span>
            Gestão de Jogadores
          </h3>
          <div className="flex gap-2 mb-6">
            <div className="relative flex-1">
              <input 
                type="text" 
                value={newPlayerNick}
                onChange={(e) => setNewPlayerNick(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddPlayerSubmit()}
                placeholder="Nick do novo jogador..."
                className="w-full bg-slate-900 border border-slate-700 rounded px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
              {addPlayerSuccess && (
                <span className="absolute right-3 top-2.5 text-emerald-400 animate-in fade-in zoom-in">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                </span>
              )}
            </div>
            <button 
              onClick={handleAddPlayerSubmit}
              className={`px-4 py-2 rounded font-bold transition-all transform active:scale-95 ${addPlayerSuccess ? 'bg-emerald-600 text-white' : 'bg-blue-600 hover:bg-blue-700'}`}
            >
              {addPlayerSuccess ? 'Pronto!' : 'Adicionar'}
            </button>
          </div>
          <div className="max-h-60 overflow-y-auto space-y-2 pr-2 custom-scrollbar">
            {players.length === 0 && <p className="text-slate-500 text-sm italic text-center py-4">Nenhum jogador cadastrado.</p>}
            {players.map(p => (
              <div key={p.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded border border-slate-700/50 hover:border-slate-600 transition-colors group">
                <span className="font-medium text-slate-200">{p.nick}</span>
                <div className="flex gap-1 opacity-60 group-hover:opacity-100 transition-opacity">
                  <button 
                    onClick={() => openEditModal('player', p.id, p.nick)}
                    className="text-slate-400 hover:text-blue-400 p-1.5 rounded hover:bg-blue-400/10 transition-colors"
                    title="Editar jogador"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
                    </svg>
                  </button>
                  <button 
                    onClick={() => openConfirmModal('player', p.id, p.nick)}
                    className="text-slate-400 hover:text-rose-500 p-1.5 rounded hover:bg-rose-500/10 transition-colors"
                    title="Excluir jogador"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
                    </svg>
                  </button>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Gestão de Temporadas */}
        <section className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-lg">
          <h3 className="text-xl font-gaming font-bold mb-4 flex items-center gap-2 text-slate-100">
            <span className="w-2 h-6 bg-purple-500 rounded-full"></span>
            Gestão de Temporadas
          </h3>
          <div className="flex gap-2 mb-6">
            <div className="relative flex-1">
              <input 
                type="text" 
                value={newSeasonName}
                onChange={(e) => setNewSeasonName(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddSeasonSubmit()}
                placeholder="Nome da nova temporada..."
                className="w-full bg-slate-900 border border-slate-700 rounded px-4 py-2 focus:ring-2 focus:ring-purple-500 outline-none transition-all"
              />
              {addSeasonSuccess && (
                <span className="absolute right-3 top-2.5 text-emerald-400 animate-in fade-in zoom-in">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                </span>
              )}
            </div>
            <button 
              onClick={handleAddSeasonSubmit}
              className={`px-4 py-2 rounded font-bold transition-all transform active:scale-95 ${addSeasonSuccess ? 'bg-emerald-600 text-white' : 'bg-purple-600 hover:bg-purple-700'}`}
            >
              {addSeasonSuccess ? 'Criado!' : 'Criar'}
            </button>
          </div>
          <div className="max-h-60 overflow-y-auto space-y-2 pr-2 custom-scrollbar">
            {seasons.length === 0 && <p className="text-slate-500 text-sm italic text-center py-4">Nenhuma temporada cadastrada.</p>}
            {seasons.map(s => (
              <div key={s.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded border border-slate-700/50 hover:border-slate-600 transition-colors group">
                <span className="font-medium text-slate-200">{s.name}</span>
                <div className="flex gap-1 opacity-60 group-hover:opacity-100 transition-opacity">
                  <button 
                    onClick={() => openEditModal('season', s.id, s.name)}
                    className="text-slate-400 hover:text-blue-400 p-1.5 rounded hover:bg-blue-400/10 transition-colors"
                    title="Editar temporada"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
                    </svg>
                  </button>
                  <button 
                    onClick={() => openConfirmModal('season', s.id, s.name)}
                    className="text-slate-400 hover:text-rose-500 p-1.5 rounded hover:bg-rose-500/10 transition-colors"
                    title="Excluir temporada"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
                    </svg>
                  </button>
                </div>
              </div>
            ))}
          </div>
        </section>
      </div>

      {/* Registro de Stats */}
      <div className="space-y-8">
        <section className="bg-slate-800 p-6 rounded-xl border border-slate-700 shadow-xl relative overflow-hidden">
          {/* Brilho de sucesso */}
          <div className={`absolute inset-0 bg-emerald-500/5 transition-opacity pointer-events-none duration-1000 ${saveSuccess ? 'opacity-100' : 'opacity-0'}`}></div>

          <h3 className="text-xl font-gaming font-bold mb-4 flex items-center gap-2 text-slate-100">
            <span className="w-2 h-6 bg-yellow-500 rounded-full"></span>
            Registrar/Atualizar Stats
          </h3>
          <form onSubmit={handleUpdateStats} className="space-y-4 relative">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm text-slate-400 mb-1">Jogador</label>
                <select 
                  value={selectedPlayerId}
                  onChange={(e) => setSelectedPlayerId(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none focus:border-yellow-500/50 hover:border-slate-600 transition-colors"
                  required
                >
                  <option value="">Selecione...</option>
                  {players.map(p => <option key={p.id} value={p.id}>{p.nick}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm text-slate-400 mb-1">Temporada</label>
                <select 
                  value={selectedSeasonId}
                  onChange={(e) => setSelectedSeasonId(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none focus:border-yellow-500/50 hover:border-slate-600 transition-colors"
                  required
                >
                  <option value="">Selecione...</option>
                  {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm text-slate-400 mb-1">Partidas</label>
                <input 
                  type="number" 
                  min="0"
                  value={matchData.matches}
                  onChange={(e) => setMatchData({...matchData, matches: Math.max(0, parseInt(e.target.value) || 0)})}
                  className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none focus:border-slate-500 transition-colors"
                />
              </div>
              <div>
                <label className="block text-sm text-slate-400 mb-1">Dano Total</label>
                <input 
                  type="number" 
                  min="0"
                  value={matchData.damage}
                  onChange={(e) => setMatchData({...matchData, damage: Math.max(0, parseInt(e.target.value) || 0)})}
                  className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 outline-none focus:border-slate-500 transition-colors"
                />
              </div>
            </div>

            <div className="grid grid-cols-3 gap-4">
              <div>
                <label className="block text-sm text-slate-400 mb-1 text-emerald-400 font-bold">Vítimas</label>
                <input 
                  type="number" 
                  min="0"
                  value={matchData.kills}
                  onChange={(e) => setMatchData({...matchData, kills: Math.max(0, parseInt(e.target.value) || 0)})}
                  className="w-full bg-slate-900 border border-emerald-500/30 rounded px-3 py-2 outline-none focus:border-emerald-500 transition-colors"
                />
              </div>
              <div>
                <label className="block text-sm text-slate-400 mb-1 text-rose-400 font-bold">Mortes</label>
                <input 
                  type="number" 
                  min="0"
                  value={matchData.deaths}
                  onChange={(e) => setMatchData({...matchData, deaths: Math.max(0, parseInt(e.target.value) || 0)})}
                  className="w-full bg-slate-900 border border-rose-500/30 rounded px-3 py-2 outline-none focus:border-rose-500 transition-colors"
                />
              </div>
              <div>
                <label className="block text-sm text-slate-400 mb-1 text-sky-400 font-bold">Assists</label>
                <input 
                  type="number" 
                  min="0"
                  value={matchData.assists}
                  onChange={(e) => setMatchData({...matchData, assists: Math.max(0, parseInt(e.target.value) || 0)})}
                  className="w-full bg-slate-900 border border-sky-500/30 rounded px-3 py-2 outline-none focus:border-sky-500 transition-colors"
                />
              </div>
            </div>

            <button 
              type="submit"
              disabled={players.length === 0 || seasons.length === 0 || isSavingStats}
              className={`w-full py-4 rounded-lg font-bold text-lg transition-all transform active:scale-95 shadow-lg flex items-center justify-center gap-2
                ${saveSuccess ? 'bg-emerald-600 text-white shadow-emerald-500/20' : 
                  isSavingStats ? 'bg-slate-700 text-slate-300' :
                  'bg-emerald-600 hover:bg-emerald-500 text-white shadow-emerald-500/20'}`}
            >
              {isSavingStats ? (
                <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
              ) : saveSuccess ? (
                <>
                  <svg className="w-6 h-6 animate-in zoom-in" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                  Estatísticas Atualizadas!
                </>
              ) : (
                'Salvar Estatísticas'
              )}
            </button>
          </form>
        </section>

        {/* Tip Informativo */}
        <div className="bg-slate-900/40 p-4 rounded-xl border border-slate-800 text-slate-400 text-sm italic group hover:border-slate-700 transition-colors">
          <div className="flex gap-3">
            <svg className="w-5 h-5 text-yellow-500 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
            <p>Dica: Após salvar, os campos de performance são limpos automaticamente, permitindo que você registre os dados do próximo jogador rapidamente.</p>
          </div>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #0f172a;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #334155;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #475569;
        }
      `}</style>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { ViewType, Player, Season, PlayerStats, FullRankingEntry } from './types';
import { INITIAL_PLAYERS, INITIAL_SEASONS, INITIAL_STATS } from './constants';
import RankingTable from './components/RankingTable';
import AdminPanel from './components/AdminPanel';
import { getRankingInsights } from './services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

// Senha mestra para demonstração - em produção isso viria de um backend
const ADMIN_PASSWORD = "x5admin2024";

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('ranking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState<boolean>(() => {
    return sessionStorage.getItem('x5_is_admin') === 'true';
  });
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);

  const [players, setPlayers] = useState<Player[]>(() => {
    const saved = localStorage.getItem('x5_players');
    return saved ? JSON.parse(saved) : INITIAL_PLAYERS;
  });
  const [seasons, setSeasons] = useState<Season[]>(() => {
    const saved = localStorage.getItem('x5_seasons');
    return saved ? JSON.parse(saved) : INITIAL_SEASONS;
  });
  const [stats, setStats] = useState<PlayerStats[]>(() => {
    const saved = localStorage.getItem('x5_stats');
    return saved ? JSON.parse(saved) : INITIAL_STATS;
  });
  const [selectedSeasonId, setSelectedSeasonId] = useState(seasons.length > 0 ? seasons[0].id : '');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loadingAi, setLoadingAi] = useState(false);

  // Persistência
  useEffect(() => {
    localStorage.setItem('x5_players', JSON.stringify(players));
    localStorage.setItem('x5_seasons', JSON.stringify(seasons));
    localStorage.setItem('x5_stats', JSON.stringify(stats));
  }, [players, seasons, stats]);

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === ADMIN_PASSWORD) {
      setIsAdminAuthenticated(true);
      sessionStorage.setItem('x5_is_admin', 'true');
      setLoginError(false);
      setAdminPasswordInput('');
    } else {
      setLoginError(true);
      setAdminPasswordInput('');
    }
  };

  const handleLogout = () => {
    setIsAdminAuthenticated(false);
    sessionStorage.removeItem('x5_is_admin');
    setView('ranking');
  };

  // Cálculo do Ranking Filtrado
  const currentRanking: FullRankingEntry[] = useMemo(() => {
    return stats
      .filter(s => s.seasonId === selectedSeasonId)
      .map(s => {
        const player = players.find(p => p.id === s.playerId);
        const kdValue = s.deaths === 0 ? s.kills : s.kills / s.deaths;
        return {
          ...s,
          nick: player?.nick || 'Desconhecido',
          kd: kdValue,
          damagePerMatch: s.matches === 0 ? 0 : s.damage / s.matches
        };
      })
      .sort((a, b) => b.kd - a.kd);
  }, [stats, selectedSeasonId, players]);

  const handleAddPlayer = (nick: string) => {
    if (!isAdminAuthenticated || !nick) return;
    const newPlayer = { id: `p${Date.now()}`, nick };
    setPlayers([...players, newPlayer]);
  };

  const handleEditPlayer = (id: string, newNick: string) => {
    if (!isAdminAuthenticated || !newNick) return;
    setPlayers(players.map(p => p.id === id ? { ...p, nick: newNick } : p));
  };

  const handleDeletePlayer = (id: string) => {
    if (!isAdminAuthenticated) return;
    setPlayers(players.filter(p => p.id !== id));
    setStats(stats.filter(s => s.playerId !== id));
  };

  const handleAddSeason = (name: string) => {
    if (!isAdminAuthenticated || !name) return;
    const newSeason = { id: `s${Date.now()}`, name };
    setSeasons([...seasons, newSeason]);
    if (!selectedSeasonId) setSelectedSeasonId(newSeason.id);
  };

  const handleEditSeason = (id: string, newName: string) => {
    if (!isAdminAuthenticated || !newName) return;
    setSeasons(seasons.map(s => s.id === id ? { ...s, name: newName } : s));
  };

  const handleDeleteSeason = (id: string) => {
    if (!isAdminAuthenticated) return;
    const updatedSeasons = seasons.filter(s => s.id !== id);
    setSeasons(updatedSeasons);
    setStats(stats.filter(s => s.seasonId !== id));
    if (selectedSeasonId === id) {
      setSelectedSeasonId(updatedSeasons.length > 0 ? updatedSeasons[0].id : '');
    }
  };

  const handleUpdateStats = (entry: Omit<PlayerStats, 'id'>) => {
    if (!isAdminAuthenticated) return;
    const existingIndex = stats.findIndex(
      s => s.playerId === entry.playerId && s.seasonId === entry.seasonId
    );

    if (existingIndex > -1) {
      // Lógica ACUMULATIVA: Soma os novos valores aos existentes
      const newStats = [...stats];
      const current = newStats[existingIndex];
      newStats[existingIndex] = {
        ...current,
        matches: current.matches + entry.matches,
        kills: current.kills + entry.kills,
        deaths: current.deaths + entry.deaths,
        assists: current.assists + entry.assists,
        damage: current.damage + entry.damage,
      };
      setStats(newStats);
    } else {
      // Cria nova entrada se não existir
      setStats([...stats, { ...entry, id: `st${Date.now()}` }]);
    }
  };

  const generateAICommentary = async () => {
    if (currentRanking.length === 0) return;
    setLoadingAi(true);
    const seasonName = seasons.find(s => s.id === selectedSeasonId)?.name || 'Temporada';
    const insight = await getRankingInsights(currentRanking, seasonName);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 bg-slate-900/90 backdrop-blur-md border-b border-slate-800 px-6 py-4 shadow-xl">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center font-gaming text-2xl font-bold italic">X5</div>
            <h1 className="text-2xl font-gaming font-bold tracking-tight bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">
              FRIENDS RANKING
            </h1>
          </div>

          <nav className="flex items-center gap-4 bg-slate-800 p-1 rounded-lg border border-slate-700">
            <button 
              onClick={() => setView('ranking')}
              className={`px-6 py-2 rounded-md font-bold transition-all ${view === 'ranking' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
              Ranking
            </button>
            <button 
              onClick={() => setView('admin')}
              className={`px-6 py-2 rounded-md font-bold transition-all ${view === 'admin' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
              Gerenciar
            </button>
            {isAdminAuthenticated && (
              <button 
                onClick={handleLogout}
                className="px-3 py-2 text-rose-500 hover:bg-rose-500/10 rounded-md transition-colors"
                title="Sair do Modo Admin"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M3 3a1 1 0 00-1 1v12a1 1 0 102 0V4a1 1 0 00-1-1zm10.293 9.293a1 1 0 001.414 1.414l3-3a1 1 0 000-1.414l-3-3a1 1 0 10-1.414 1.414L14.586 9H7a1 1 0 100 2h7.586l-1.293 1.293z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {view === 'ranking' ? (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="w-full md:w-auto">
                <label className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-2 block">Selecionar Temporada</label>
                <select 
                  value={selectedSeasonId}
                  onChange={(e) => { setSelectedSeasonId(e.target.value); setAiInsight(''); }}
                  className="w-full md:w-72 bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-blue-500 shadow-lg"
                >
                  {seasons.length === 0 && <option value="">Nenhuma temporada criada</option>}
                  {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>

              <div className="flex gap-4">
                <button 
                  onClick={generateAICommentary}
                  disabled={loadingAi || currentRanking.length === 0}
                  className="flex items-center gap-2 bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 px-6 py-3 rounded-xl font-bold shadow-lg transition-transform active:scale-95 disabled:opacity-50"
                >
                  {loadingAi ? (
                    <span className="flex items-center gap-2">
                      <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      Analisando...
                    </span>
                  ) : (
                    <>✨ Análise por IA</>
                  )}
                </button>
              </div>
            </div>

            {aiInsight && (
              <div className="bg-slate-800/80 border border-purple-500/30 p-6 rounded-2xl relative overflow-hidden shadow-2xl">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <svg className="w-24 h-24" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                </div>
                <h4 className="text-purple-400 font-bold mb-2 flex items-center gap-2">
                  <span className="animate-pulse">✨</span> Comentário do Analista
                </h4>
                <p className="text-slate-300 leading-relaxed italic">{aiInsight}</p>
              </div>
            )}

            {currentRanking.length > 0 ? (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-slate-900/50 p-6 rounded-2xl border border-slate-800">
                    <h3 className="text-xl font-gaming font-bold mb-6 flex items-center gap-2">
                      <span className="w-2 h-6 bg-emerald-500 rounded-full"></span>
                      Performance Comparada (K/D)
                    </h3>
                    <div className="h-[300px] w-full">
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={currentRanking}>
                          <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                          <XAxis dataKey="nick" stroke="#94a3b8" />
                          <YAxis stroke="#94a3b8" />
                          <Tooltip 
                            contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px' }}
                            itemStyle={{ color: '#fff' }}
                          />
                          <Bar dataKey="kd" radius={[4, 4, 0, 0]}>
                            {currentRanking.map((entry, index) => (
                              <Cell key={`cell-${index}`} fill={entry.kd >= 1.5 ? '#10b981' : entry.kd >= 1.0 ? '#3b82f6' : '#f43f5e'} />
                            ))}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                    </div>
                </div>

                <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800 flex flex-col justify-center text-center">
                    <div className="mb-4">
                      <p className="text-slate-400 uppercase tracking-widest text-sm mb-1">Total de Vítimas na Temp</p>
                      <p className="text-5xl font-gaming font-bold text-emerald-400">
                        {currentRanking.reduce((acc, curr) => acc + curr.kills, 0)}
                      </p>
                    </div>
                    <div className="h-px bg-slate-800 my-6"></div>
                    <div>
                      <p className="text-slate-400 uppercase tracking-widest text-sm mb-1">Média de Dano</p>
                      <p className="text-4xl font-gaming font-bold text-orange-400">
                        {(currentRanking.reduce((acc, curr) => acc + curr.damage, 0) / (currentRanking.length || 1)).toLocaleString('pt-BR', { maximumFractionDigits: 0 })}
                      </p>
                    </div>
                </div>
              </div>
            ) : (
               <div className="text-center py-20 bg-slate-900/30 border border-slate-800 rounded-2xl border-dashed">
                 <p className="text-slate-500 text-lg">Sem dados de ranking para exibir. Comece cadastrando estatísticas no painel de gerenciamento.</p>
               </div>
            )}

            {currentRanking.length > 0 && <RankingTable data={currentRanking} />}
          </div>
        ) : !isAdminAuthenticated ? (
          <div className="max-w-md mx-auto mt-20 p-8 bg-slate-900 border border-slate-800 rounded-2xl shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="w-16 h-16 bg-blue-500/10 rounded-full flex items-center justify-center mx-auto mb-6 text-blue-500">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
              </svg>
            </div>
            <h2 className="text-2xl font-gaming font-bold text-center mb-2">Acesso Restrito</h2>
            <p className="text-slate-400 text-center mb-8">Digite a chave de administrador para gerenciar jogadores e temporadas.</p>

            <form onSubmit={handleAdminLogin} className="space-y-4">
              <div>
                <input 
                  type="password" 
                  value={adminPasswordInput}
                  onChange={(e) => setAdminPasswordInput(e.target.value)}
                  placeholder="Senha Administrativa"
                  className={`w-full bg-slate-800 border ${loginError ? 'border-rose-500 ring-rose-500' : 'border-slate-700'} rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-blue-500 transition-all`}
                  autoFocus
                />
                {loginError && <p className="text-rose-500 text-xs mt-2 font-bold animate-bounce">Chave de acesso incorreta.</p>}
              </div>
              <button 
                type="submit"
                className="w-full bg-blue-600 hover:bg-blue-700 py-3 rounded-xl font-bold shadow-lg shadow-blue-500/20 transition-all active:scale-95"
              >
                Entrar no Painel
              </button>
            </form>
          </div>
        ) : (
          <div className="animate-in fade-in slide-in-from-right-4 duration-500">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-3xl font-gaming font-bold">Administração do Painel</h2>
              <div className="bg-emerald-500/10 text-emerald-400 px-3 py-1 rounded-full text-xs font-bold border border-emerald-500/20 flex items-center gap-1">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
                MODO ADMINISTRADOR ATIVO
              </div>
            </div>
            <AdminPanel 
              players={players} 
              seasons={seasons} 
              stats={stats}
              onAddPlayer={handleAddPlayer}
              onEditPlayer={handleEditPlayer}
              onDeletePlayer={handleDeletePlayer}
              onAddSeason={handleAddSeason}
              onEditSeason={handleEditSeason}
              onDeleteSeason={handleDeleteSeason}
              onUpdateStats={handleUpdateStats}
            />
          </div>
        )}
      </main>

      <footer className="mt-20 border-t border-slate-800 py-10 text-center text-slate-500 text-sm">
        <p>© 2024 X5 dos Amigos - Desenvolvido com Gemini AI</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Player, Season, PlayerStats } from '../types';

interface AdminPanelProps {
  players: Player[];
  seasons: Season[];
  stats: PlayerStats[];
  onAddPlayer: (nick: string) => void;
  onEditPlayer: (id: string, newNick: string) => void;
  onDeletePlayer: (id: string) => void;
  onAddSeason: (name: string) => void;
  onEditSeason: (id: string, newName: string) => void;
  onDeleteSeason: (id: string) => void;
  onUpdateStats: (entry: Omit<PlayerStats, 'id'>) => void;
}

interface ConfirmModalState {
  isOpen: boolean;
  type: 'player' | 'season' | null;
  id: string;
  name: string;
}

interface EditModalState {
  isOpen: boolean;
  type: 'player' | 'season' | null;
  id: string;
  value: string;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  players, 
  seasons, 
  onAddPlayer, 
  onEditPlayer,
  onDeletePlayer,
  onAddSeason, 
  onEditSeason,
  onDeleteSeason,
  onUpdateStats 
}) => {
  const [newPlayerNick, setNewPlayerNick] = useState('');
  const [newSeasonName, setNewSeasonName] = useState('');

  const [selectedPlayerId, setSelectedPlayerId] = useState('');
  const [selectedSeasonId, setSelectedSeasonId] = useState('');
  const [matchData, setMatchData] = useState({
    matches: 0,
    kills: 0,
    deaths: 0,
    assists: 0,
    damage: 0
  });

  // Estados de feedback visual
  const [isSavingStats, setIsSavingStats] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [addPlayerSuccess, setAddPlayerSuccess] = useState(false);
  const [addSeasonSuccess, setAddSeasonSuccess] = useState(false);

  const [confirmModal, setConfirmModal] = useState<ConfirmModalState>({
    isOpen: false,
    type: null,
    id: '',
    name: ''
  });

  const [editModal, setEditModal] = useState<EditModalState>({
    isOpen: false,
    type: null,
    id: '',
    value: ''
  });

  const handleUpdateStats = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPlayerId || !selectedSeasonId) return;

    setIsSavingStats(true);

    // Simula um pequeno delay para feedback de carregamento
    setTimeout(() => {
      onUpdateStats({
        playerId: selectedPlayerId,
        seasonId: selectedSeasonId,
        ...matchData
      });

      setIsSavingStats(false);
      setSaveSuccess(true);

      // Limpa apenas os dados numéricos após salvar
      setMatchData({
        matches: 0,
        kills: 0,
        deaths: 0,
        assists: 0,
        damage: 0
      });

      // Remove mensagem de sucesso após 3 segundos
      setTimeout(() => setSaveSuccess(false), 3000);
    }, 400);
  };

  const handleAddPlayerSubmit = () => {
    if (!newPlayerNick.trim()) return;
    onAddPlayer(newPlayerNick);
    setNewPlayerNick('');
    setAddPlayerSuccess(true);
    setTimeout(() => setAddPlayerSuccess(false), 2000);
  };

  const handleAddSeasonSubmit = () => {
    if (!newSeasonName.trim()) return;
    onAddSeason(newSeasonName);
    setNewSeasonName('');
    setAddSeasonSuccess(true);
    setTimeout(() => setAddSeasonSuccess(false), 2000);
  };

  const openConfirmModal = (type: 'player' | 'season', id: string, name: string) => {
    setConfirmModal({ isOpen: true, type, id, name });
  };

  const closeConfirmModal = () => {
    setConfirmModal({ isOpen: false, type: null, id: '', name: '' });
  };

  const openEditModal = (type: 'player' | 'season', id: string, value: string) => {
    setEditModal({ isOpen: true, type, id, value });
  };

  const closeEditModal = () => {
    setEditModal({ isOpen: false, type: null, id: '', value: '' });
