          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center font-gaming text-2xl font-bold italic">X5</div>
            <h1 className="text-2xl font-gaming font-bold tracking-tight bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">
              FRIENDS RANKING
            </h1>
          </div>

          <nav className="flex items-center gap-4 bg-slate-800 p-1 rounded-lg border border-slate-700">
            <button 
              onClick={() => setView('ranking')}
              className={`px-6 py-2 rounded-md font-bold transition-all ${view === 'ranking' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
              Ranking
            </button>
            <button 
              onClick={() => setView('admin')}
              className={`px-6 py-2 rounded-md font-bold transition-all ${view === 'admin' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
              Gerenciar
            </button>
            {isAdminAuthenticated && (
              <button 
                onClick={handleLogout}
                className="px-3 py-2 text-rose-500 hover:bg-rose-500/10 rounded-md transition-colors"
                title="Sair do Modo Admin"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M3 3a1 1 0 00-1 1v12a1 1 0 102 0V4a1 1 0 00-1-1zm10.293 9.293a1 1 0 001.414 1.414l3-3a1 1 0 000-1.414l-3-3a1 1 0 10-1.414 1.414L14.586 9H7a1 1 0 100 2h7.586l-1.293 1.293z" clipRule="evenodd" />
                </svg>
              </button>
            )}
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {view === 'ranking' ? (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="w-full md:w-auto">
                <label className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-2 block">Selecionar Temporada</label>
                <select 
                  value={selectedSeasonId}
                  onChange={(e) => { setSelectedSeasonId(e.target.value); setAiInsight(''); }}
                  className="w-full md:w-72 bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-blue-500 shadow-lg"
                >
                  {seasons.length === 0 && <option value="">Nenhuma temporada criada</option>}
                  {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>

              <div className="flex gap-4">
                <button 
                  onClick={generateAICommentary}
                  disabled={loadingAi || currentRanking.length === 0}
                  className="flex items-center gap-2 bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 px-6 py-3 rounded-xl font-bold shadow-lg transition-transform active:scale-95 disabled:opacity-50"
                >
                  {loadingAi ? (
                    <span className="flex items-center gap-2">
                      <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      Analisando...
                    </span>
                  ) : (
                    <>✨ Análise por IA</>
                  )}
                </button>
              </div>
            </div>

            {aiInsight && (
              <div className="bg-slate-800/80 border border-purple-500/30 p-6 rounded-2xl relative overflow-hidden shadow-2xl">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <svg className="w-24 h-24" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                </div>
                <h4 className="text-purple-400 font-bold mb-2 flex items-center gap-2">
                  <span className="animate-pulse">✨</span> Comentário do Analista
                </h4>
                <p className="text-slate-300 leading-relaxed italic">{aiInsight}</p>
              </div>
            )}

            {currentRanking.length > 0 ? (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-slate-900/50 p-6 rounded-2xl border border-slate-800">
                    <h3 className="text-xl font-gaming font-bold mb-6 flex items-center gap-2">
                      <span className="w-2 h-6 bg-emerald-500 rounded-full"></span>
                      Performance Comparada (K/D)
                    </h3>
                    <div className="h-[300px] w-full">
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={currentRanking}>
                          <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                          <XAxis dataKey="nick" stroke="#94a3b8" />
                          <YAxis stroke="#94a3b8" />
                          <Tooltip 
                            contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px' }}
                            itemStyle={{ color: '#fff' }}
                          />
                          <Bar dataKey="kd" radius={[4, 4, 0, 0]}>
                            {currentRanking.map((entry, index) => (
                              <Cell key={`cell-${index}`} fill={entry.kd >= 1.5 ? '#10b981' : entry.kd >= 1.0 ? '#3b82f6' : '#f43f5e'} />
                            ))}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                    </div>
                </div>

                <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800 flex flex-col justify-center text-center">
                    <div className="mb-4">
                      <p className="text-slate-400 uppercase tracking-widest text-sm mb-1">Total de Vítimas na Temp</p>
                      <p className="text-5xl font-gaming font-bold text-emerald-400">
                        {currentRanking.reduce((acc, curr) => acc + curr.kills, 0)}
                      </p>
                    </div>
                    <div className="h-px bg-slate-800 my-6"></div>
                    <div>
                      <p className="text-slate-400 uppercase tracking-widest text-sm mb-1">Média de Dano</p>
                      <p className="text-4xl font-gaming font-bold text-orange-400">
                        {(currentRanking.reduce((acc, curr) => acc + curr.damage, 0) / (currentRanking.length || 1)).toLocaleString('pt-BR', { maximumFractionDigits: 0 })}
                      </p>
                    </div>
                </div>
              </div>
            ) : (
               <div className="text-center py-20 bg-slate-900/30 border border-slate-800 rounded-2xl border-dashed">
                 <p className="text-slate-500 text-lg">Sem dados de ranking para exibir. Comece cadastrando estatísticas no painel de gerenciamento.</p>
               </div>
            )}

            {currentRanking.length > 0 && <RankingTable data={currentRanking} />}
          </div>
        ) : !isAdminAuthenticated ? (
          <div className="max-w-md mx-auto mt-20 p-8 bg-slate-900 border border-slate-800 rounded-2xl shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="w-16 h-16 bg-blue-500/10 rounded-full flex items-center justify-center mx-auto mb-6 text-blue-500">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
              </svg>
            </div>
            <h2 className="text-2xl font-gaming font-bold text-center mb-2">Acesso Restrito</h2>
            <p className="text-slate-400 text-center mb-8">Digite a chave de administrador para gerenciar o banco de dados e estatísticas.</p>

            <form onSubmit={handleAdminLogin} className="space-y-4">
              <div>
                <input 
                  type="password" 
                  value={adminPasswordInput}
                  onChange={(e) => setAdminPasswordInput(e.target.value)}
                  placeholder="Senha Administrativa"
                  className={`w-full bg-slate-800 border ${loginError ? 'border-rose-500 ring-rose-500' : 'border-slate-700'} rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-blue-500 transition-all`}
                  autoFocus
                />
                {loginError && <p className="text-rose-500 text-xs mt-2 font-bold animate-bounce">Chave de acesso incorreta.</p>}
              </div>
              <button 
                type="submit"
                className="w-full bg-blue-600 hover:bg-blue-700 py-3 rounded-xl font-bold shadow-lg shadow-blue-500/20 transition-all active:scale-95"
              >
                Entrar no Painel
              </button>
            </form>
          </div>
        ) : (
          <div className="animate-in fade-in slide-in-from-right-4 duration-500">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-3xl font-gaming font-bold">Gerenciamento de Dados</h2>
              <div className="bg-emerald-500/10 text-emerald-400 px-3 py-1 rounded-full text-xs font-bold border border-emerald-500/20 flex items-center gap-1">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
                SESSÃO ADMINISTRATIVA ATIVA
              </div>
            </div>
            <AdminPanel 
              players={players} 
              seasons={seasons} 
              stats={stats}
              onAddPlayer={handleAddPlayer}
              onEditPlayer={handleEditPlayer}
              onDeletePlayer={handleDeletePlayer}
              onAddSeason={handleAddSeason}
              onEditSeason={handleEditSeason}
              onDeleteSeason={handleDeleteSeason}
              onUpdateStats={handleUpdateStats}
              onResetData={handleResetData}
              onSetView={setView}
            />
          </div>
        )}
      </main>

      <footer className="mt-20 border-t border-slate-800 py-10 text-center text-slate-500 text-sm">
        <p>© 2024 X5 dos Amigos - Desenvolvido com Gemini AI</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Player, Season, PlayerStats, ViewType } from '../types';

interface AdminPanelProps {
  players: Player[];
  seasons: Season[];
  stats: PlayerStats[];
  onAddPlayer: (nick: string) => void;
  onEditPlayer: (id: string, newNick: string) => void;
  onDeletePlayer: (id: string) => void;
  onAddSeason: (name: string) => void;
  onEditSeason: (id: string, newName: string) => void;
  onDeleteSeason: (id: string) => void;
  onUpdateStats: (entry: Omit<PlayerStats, 'id'>) => void;
  onResetData: () => void;
  onSetView: (view: ViewType) => void;
}

interface ConfirmModalState {
  isOpen: boolean;
  type: 'player' | 'season' | 'reset' | null;
  id: string;
  name: string;
}

interface EditModalState {
  isOpen: boolean;
  type: 'player' | 'season' | null;
  id: string;
  value: string;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  players, 
  seasons, 
  stats,
  onAddPlayer, 
  onEditPlayer,
  onDeletePlayer,
  onAddSeason, 
  onEditSeason,
  onDeleteSeason,
  onUpdateStats,
  onResetData,
  onSetView
}) => {
  const [newPlayerNick, setNewPlayerNick] = useState('');
  const [newSeasonName, setNewSeasonName] = useState('');
  const [selectedPlayerId, setSelectedPlayerId] = useState('');
  const [selectedSeasonId, setSelectedSeasonId] = useState('');
  const [matchData, setMatchData] = useState({
    matches: 0,
    kills: 0,
    deaths: 0,
    assists: 0,
    damage: 0
  });

  // Estados de feedback
  const [isSavingStats, setIsSavingStats] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [addPlayerSuccess, setAddPlayerSuccess] = useState(false);
  const [addSeasonSuccess, setAddSeasonSuccess] = useState(false);

  const [confirmModal, setConfirmModal] = useState<ConfirmModalState>({
    isOpen: false,
    type: null,
    id: '',
    name: ''
  });

  const [editModal, setEditModal] = useState<EditModalState>({
    isOpen: false,
    type: null,
    id: '',
    value: ''
  });

  const playerInputRef = useRef<HTMLInputElement>(null);
  const seasonInputRef = useRef<HTMLInputElement>(null);

  const handleUpdateStats = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPlayerId || !selectedSeasonId) return;

    setIsSavingStats(true);
    setTimeout(() => {
      onUpdateStats({
        playerId: selectedPlayerId,
        seasonId: selectedSeasonId,
        ...matchData
      });

      setIsSavingStats(false);
      setSaveSuccess(true);
      setMatchData({ matches: 0, kills: 0, deaths: 0, assists: 0, damage: 0 });
      setTimeout(() => setSaveSuccess(false), 5000);
    }, 600);
  };

  const handleAddPlayerSubmit = () => {
    if (!newPlayerNick.trim()) return;
    onAddPlayer(newPlayerNick);
    setNewPlayerNick('');
    setAddPlayerSuccess(true);
    setTimeout(() => setAddPlayerSuccess(false), 2000);
    playerInputRef.current?.focus();
  };

  const handleAddSeasonSubmit = () => {
    if (!newSeasonName.trim()) return;
    onAddSeason(newSeasonName);
    setNewSeasonName('');
    setAddSeasonSuccess(true);
    setTimeout(() => setAddSeasonSuccess(false), 2000);
    seasonInputRef.current?.focus();
  };

  const openConfirmModal = (type: 'player' | 'season' | 'reset', id: string = '', name: string = '') => {
    setConfirmModal({ isOpen: true, type, id, name });
  };

  const executeDeleteOrReset = () => {
    if (confirmModal.type === 'player') onDeletePlayer(confirmModal.id);
    else if (confirmModal.type === 'season') onDeleteSeason(confirmModal.id);
    else if (confirmModal.type === 'reset') onResetData();
    setConfirmModal({ isOpen: false, type: null, id: '', name: '' });
  };

  const openEditModal = (type: 'player' | 'season', id: string, value: string) => {
    setEditModal({ isOpen: true, type, id, value });
  };

  const executeEdit = () => {
    if (!editModal.value.trim()) return;
    if (editModal.type === 'player') onEditPlayer(editModal.id, editModal.value);
    else if (editModal.type === 'season') onEditSeason(editModal.id, editModal.value);
    setEditModal({ isOpen: false, type: null, id: '', value: '' });
  };

  const handleExportData = () => {
    const data = { players, seasons, stats };
    navigator.clipboard.writeText(JSON.stringify(data, null, 2));
    alert("Dados do 'banco de dados' copiados para a área de transferência!");
  };

  return (
    <div className="space-y-10 pb-20">
      {/* Overview Dashboard */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-500/20 rounded-xl flex items-center justify-center text-blue-400">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path></svg>
          </div>
          <div>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Jogadores</p>
            <p className="text-2xl font-gaming font-bold">{players.length}</p>
          </div>
        </div>
        <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl flex items-center gap-4">
          <div className="w-12 h-12 bg-purple-500/20 rounded-xl flex items-center justify-center text-purple-400">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
          </div>
          <div>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Temporadas</p>
            <p className="text-2xl font-gaming font-bold">{seasons.length}</p>
          </div>
        </div>
        <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl flex items-center gap-4">
          <div className="w-12 h-12 bg-emerald-500/20 rounded-xl flex items-center justify-center text-emerald-400">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"></path></svg>
          </div>
          <div>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Registros</p>
            <p className="text-2xl font-gaming font-bold">{stats.length}</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Lado Esquerdo: Gestão de Entidades */}
        <div className="space-y-8">
          <section className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-lg">
            <h3 className="text-xl font-gaming font-bold mb-4 flex items-center gap-2">
              <span className="w-2 h-6 bg-blue-500 rounded-full"></span>
              Jogadores no Banco
            </h3>
            <div className="flex gap-2 mb-6">
              <input 
                ref={playerInputRef}
                type="text" 
                value={newPlayerNick}
                onChange={(e) => setNewPlayerNick(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddPlayerSubmit()}
                placeholder="Nick do novo jogador..."
                className="flex-1 bg-slate-900 border border-slate-700 rounded-xl px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
              <button 
                onClick={handleAddPlayerSubmit}
                className={`px-6 py-2 rounded-xl font-bold transition-all ${addPlayerSuccess ? 'bg-emerald-600 text-white' : 'bg-blue-600 hover:bg-blue-700'}`}
              >
                {addPlayerSuccess ? 'OK!' : 'Adicionar'}
              </button>
            </div>
            <div className="max-h-48 overflow-y-auto space-y-2 pr-2 custom-scrollbar">
              {players.map(p => (
                <div key={p.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded-xl border border-slate-700/50 group">
                  <span className="font-medium text-slate-200">{p.nick}</span>
                  <div className="flex gap-2 opacity-40 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => openEditModal('player', p.id, p.nick)} className="text-slate-400 hover:text-blue-400 p-1.5 transition-colors">
                      <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" /></svg>
                    </button>
                    <button onClick={() => openConfirmModal('player', p.id, p.nick)} className="text-slate-400 hover:text-rose-500 p-1.5 transition-colors">
                      <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </section>

          <section className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-lg">
            <h3 className="text-xl font-gaming font-bold mb-4 flex items-center gap-2">
              <span className="w-2 h-6 bg-purple-500 rounded-full"></span>
              Temporadas
            </h3>
            <div className="flex gap-2 mb-6">
              <input 
                ref={seasonInputRef}
                type="text" 
                value={newSeasonName}
                onChange={(e) => setNewSeasonName(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddSeasonSubmit()}
                placeholder="Nome da temporada..."
                className="flex-1 bg-slate-900 border border-slate-700 rounded-xl px-4 py-2 focus:ring-2 focus:ring-purple-500 outline-none transition-all"
              />
              <button 
                onClick={handleAddSeasonSubmit}
                className={`px-6 py-2 rounded-xl font-bold transition-all ${addSeasonSuccess ? 'bg-emerald-600 text-white' : 'bg-purple-600 hover:bg-purple-700'}`}
              >
                {addSeasonSuccess ? 'Criada!' : 'Criar'}
              </button>
            </div>
            <div className="max-h-48 overflow-y-auto space-y-2 pr-2 custom-scrollbar">
              {seasons.map(s => (
                <div key={s.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded-xl border border-slate-700/50 group">
                  <span className="font-medium text-slate-200">{s.name}</span>
                  <div className="flex gap-2 opacity-40 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => openEditModal('season', s.id, s.name)} className="text-slate-400 hover:text-blue-400 p-1.5 transition-colors">
                      <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" /></svg>
