import { Player, Season, PlayerStats, ViewType } from '../types';
import { db } from '../services/databaseService';

interface AdminPanelProps {
  players: Player[];
  seasons: Season[];
  stats: PlayerStats[];
  onAddPlayer: (nick: string) => void;
  onEditPlayer: (id: string, newNick: string) => void;
  onDeletePlayer: (id: string) => void;
  onAddSeason: (name: string) => void;
  onEditSeason: (id: string, newName: string) => void;
  onDeleteSeason: (id: string) => void;
  onUpdateStats: (entry: Omit<PlayerStats, 'id'>) => void;
  onResetData: () => void;
  onSetView: (view: ViewType) => void;
  onPublish: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  players, seasons, stats,
  onAddPlayer, onDeletePlayer,
  onAddSeason, onDeleteSeason,
  onUpdateStats, onResetData, onSetView, onPublish
}) => {
  const [newPlayerNick, setNewPlayerNick] = useState('');
  const [newSeasonName, setNewSeasonName] = useState('');
  const [selectedPlayerId, setSelectedPlayerId] = useState('');
  const [selectedSeasonId, setSelectedSeasonId] = useState('');
  const [matchData, setMatchData] = useState({ matches: 0, kills: 0, deaths: 0, assists: 0, damage: 0 });

  const [isSaving, setIsSaving] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);

  // Estados para configuração manual
  const [manualUrl, setManualUrl] = useState('');
  const [manualKey, setManualKey] = useState('');
  const [showConfig, setShowConfig] = useState(false);
  const [isConnected, setIsConnected] = useState(db.isCloudEnabled());

  useEffect(() => {
    // Carrega chaves salvas ou atuais ao montar
    setManualUrl(localStorage.getItem('supabase_url') || '');
    setManualKey(localStorage.getItem('supabase_anon_key') || '');
    const connected = db.isCloudEnabled();
    setIsConnected(connected);
    // Se não estiver conectado, mostra config automaticamente
    if (!connected) setShowConfig(true);
  }, []);

  const handleUpdateStats = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPlayerId || !selectedSeasonId) return;
    setIsSaving(true);

    onUpdateStats({
      playerId: selectedPlayerId,
      seasonId: selectedSeasonId,
      ...matchData
    });

    await new Promise(r => setTimeout(r, 600));
    setIsSaving(false);
    setSaveSuccess(true);
    setMatchData({ matches: 0, kills: 0, deaths: 0, assists: 0, damage: 0 });
    setTimeout(() => setSaveSuccess(false), 3500);
  };

  const saveManualConfig = () => {
    if (manualUrl && manualKey) {
      db.setCloudKeys(manualUrl.trim(), manualKey.trim());
      alert("Chaves salvas! A página será recarregada para aplicar a conexão.");
      window.location.reload();
    } else {
      alert("Preencha URL e Chave.");
    }
  };

  const clearManualConfig = () => {
    db.clearCloudKeys();
    setManualUrl('');
    setManualKey('');
    window.location.reload();
  };

  return (
    <div className="space-y-8 animate-in slide-in-from-right-8 duration-500">
      {/* SEÇÃO DE DIAGNÓSTICO E CONFIGURAÇÃO */}
      <div className={`border p-6 rounded-2xl shadow-xl transition-all ${isConnected ? 'bg-slate-900 border-slate-800' : 'bg-rose-950/20 border-rose-500/50'}`}>
        <div className="flex justify-between items-center mb-2">
          <h3 className="text-sm font-bold uppercase tracking-widest flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${isConnected ? 'bg-emerald-500 animate-pulse' : 'bg-rose-500'}`}></div>
            Status da Nuvem: {isConnected ? <span className="text-emerald-500">Conectado ao Supabase</span> : <span className="text-rose-500">Desconectado / Local</span>}
          </h3>
          <button onClick={() => setShowConfig(!showConfig)} className="text-xs text-blue-400 hover:underline bg-slate-800 px-3 py-1 rounded-lg">
            {showConfig ? 'Ocultar Configuração' : '⚙️ Configurar Conexão'}
          </button>
        </div>

        {!isConnected && (
            <p className="text-xs text-rose-300 mb-4">
              ⚠️ O Painel não está conseguindo salvar na nuvem. Verifique as chaves abaixo ou edite o arquivo <code>databaseService.ts</code>.
            </p>
        )}

        {showConfig && (
          <div className="space-y-4 animate-in fade-in slide-in-from-top-2 duration-300 border-t border-slate-700/50 pt-4 mt-4 bg-slate-950/50 p-4 rounded-xl">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 font-bold ml-1 uppercase">Supabase URL</label>
                <input 
                  type="text" 
                  value={manualUrl} 
                  onChange={(e) => setManualUrl(e.target.value)}
                  placeholder="https://seu-projeto.supabase.co" 
                  className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2 text-xs outline-none focus:border-emerald-500 text-emerald-300 font-mono"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 font-bold ml-1 uppercase">Anon Key</label>
                <input 
                  type="password" 
                  value={manualKey} 
                  onChange={(e) => setManualKey(e.target.value)}
                  placeholder="Sua chave pública (anon)..." 
                  className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2 text-xs outline-none focus:border-emerald-500 text-emerald-300 font-mono"
                />
              </div>
            </div>
            <div className="flex gap-2">
              <button 
                onClick={saveManualConfig}
                className="flex-1 bg-emerald-600 hover:bg-emerald-500 text-white text-[10px] font-bold py-3 rounded-lg transition-all shadow-lg shadow-emerald-900/20"
              >
                SALVAR E RECONECTAR
              </button>
              <button 
                onClick={clearManualConfig}
                className="bg-rose-900/30 hover:bg-rose-900/50 text-rose-500 text-[10px] font-bold px-4 py-3 rounded-lg transition-all border border-rose-900/30"
              >
                LIMPAR
              </button>
            </div>
            <p className="text-[10px] text-slate-500 text-center italic mt-2">
              Dica: Para conexão automática sem login, preencha as constantes <code>HARDCODED</code> no arquivo <code>services/databaseService.ts</code>.
            </p>
          </div>
        )}
      </div>

      {/* BOTÃO DE PUBLICAÇÃO GLOBAL */}
      {isConnected ? (
        <div className="bg-emerald-600/10 border border-emerald-500/20 p-6 rounded-2xl flex flex-col md:flex-row items-center justify-between gap-4">
           <div>
             <h4 className="text-emerald-400 font-bold">Publicar Dados</h4>
             <p className="text-xs text-slate-400">Envia as alterações locais para o banco de dados oficial.</p>
           </div>
           <button onClick={onPublish} className="bg-emerald-600 hover:bg-emerald-500 px-8 py-3 rounded-xl font-bold transition-all shadow-lg shadow-emerald-500/20 flex items-center gap-2 text-white">
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
             SINCRONIZAR AGORA
           </button>
        </div>
      ) : (
        <div className="bg-rose-600/10 border border-rose-500/20 p-4 rounded-xl text-center">
            <p className="text-rose-400 font-bold text-sm">Conexão necessária para publicar dados.</p>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* GERENCIAR JOGADORES */}
        <div className="space-y-8">
          <section className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800">
            <h3 className="text-lg font-bold mb-6 text-blue-400 flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z"></path></svg>
              Gerenciar Jogadores
            </h3>
            <div className="flex gap-2 mb-6">
              <input type="text" value={newPlayerNick} onChange={(e) => setNewPlayerNick(e.target.value)} placeholder="Nick do player..." className="flex-1 bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 outline-none focus:ring-1 focus:ring-blue-500 transition-all text-slate-100" />
              <button onClick={() => { if(newPlayerNick) { onAddPlayer(newPlayerNick); setNewPlayerNick(''); } }} className="bg-blue-600 hover:bg-blue-500 px-6 py-3 rounded-xl font-bold transition-all shadow-lg shadow-blue-500/20 text-white">Add</button>
            </div>
            <div className="max-h-56 overflow-y-auto space-y-2 custom-scrollbar pr-2">
              {players.length === 0 && <p className="text-xs text-slate-600 text-center py-4">Nenhum jogador cadastrado.</p>}
              {players.map(p => (
                <div key={p.id} className="flex justify-between items-center p-3 bg-slate-800/40 rounded-xl border border-slate-700/50 hover:bg-slate-800 transition-all">
                  <span className="text-slate-200 font-bold">{p.nick}</span>
                  <button onClick={() => onDeletePlayer(p.id)} className="text-rose-500 p-2 hover:bg-rose-500/10 rounded-lg transition-colors">
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                  </button>
                </div>
              ))}
            </div>
          </section>

          {/* GERENCIAR TEMPORADAS */}
          <section className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800">
            <h3 className="text-lg font-bold mb-6 text-purple-400 flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
              Gerenciar Temporadas
            </h3>
            <div className="flex gap-2 mb-6">
              <input type="text" value={newSeasonName} onChange={(e) => setNewSeasonName(e.target.value)} placeholder="Nome da Season..." className="flex-1 bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 outline-none focus:ring-1 focus:ring-purple-500 transition-all text-slate-100" />
              <button onClick={() => { if(newSeasonName) { onAddSeason(newSeasonName); setNewSeasonName(''); } }} className="bg-purple-600 hover:bg-purple-500 px-6 py-3 rounded-xl font-bold transition-all shadow-lg shadow-purple-500/20 text-white">Criar</button>
            </div>
            <div className="max-h-56 overflow-y-auto space-y-2 custom-scrollbar pr-2">
            {seasons.length === 0 && <p className="text-xs text-slate-600 text-center py-4">Nenhuma temporada criada.</p>}
              {seasons.map(s => (
                <div key={s.id} className="flex justify-between items-center p-3 bg-slate-800/40 rounded-xl border border-slate-700/50 hover:bg-slate-800 transition-all">
                  <span className="text-slate-200 font-bold">{s.name}</span>
                  <button onClick={() => onDeleteSeason(s.id)} className="text-rose-500 p-2 hover:bg-rose-500/10 rounded-lg transition-colors">
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                  </button>
                </div>
              ))}
            </div>
          </section>
        </div>

        <div className="space-y-8">
          <section className="bg-slate-800 p-8 rounded-3xl border border-slate-700 shadow-2xl relative overflow-hidden h-full">
            {saveSuccess && (
              <div className="absolute inset-0 bg-emerald-600/95 backdrop-blur-md flex flex-col items-center justify-center animate-in zoom-in duration-300 z-30">
                <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-2xl">
                  <svg className="w-12 h-12 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                </div>
                <h4 className="text-2xl font-bold text-white mb-2">Registrado!</h4>
                <p className="text-emerald-100 mb-8 opacity-80 text-sm text-center">Os dados foram atualizados localmente.</p>
                <button onClick={() => setSaveSuccess(false)} className="bg-emerald-800 hover:bg-emerald-900 text-white px-8 py-3 rounded-xl font-bold transition-all">Novo Registro</button>
              </div>
            )}

            <h3 className="text-xl font-gaming font-bold mb-8 text-emerald-400 flex items-center gap-3">
              <span className="w-1.5 h-8 bg-emerald-500 rounded-full"></span>
              Registrar Pontuação
            </h3>

            <form onSubmit={handleUpdateStats} className="space-y-8">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Atleta</label>
                    <select value={selectedPlayerId} onChange={(e) => setSelectedPlayerId(e.target.value)} required className="w-full bg-slate-900 border border-slate-700 rounded-2xl p-4 outline-none focus:border-emerald-500 transition-all text-slate-200 appearance-none cursor-pointer shadow-inner">
                      <option value="">Selecione o Jogador</option>
                      {players.map(p => <option key={p.id} value={p.id}>{p.nick}</option>)}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Temporada</label>
                    <select value={selectedSeasonId} onChange={(e) => setSelectedSeasonId(e.target.value)} required className="w-full bg-slate-900 border border-slate-700 rounded-2xl p-4 outline-none focus:border-emerald-500 transition-all text-slate-200 appearance-none cursor-pointer shadow-inner">
                      <option value="">Selecione a Temporada</option>
                      {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    </select>
                  </div>
               </div>

               <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Partidas (+)</label>
                    <input type="number" min="0" value={matchData.matches} onChange={e => setMatchData({...matchData, matches: parseInt(e.target.value) || 0})} className="w-full bg-slate-900 border border-slate-700 rounded-2xl p-4 text-slate-100 outline-none focus:border-emerald-500 transition-all" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Dano (+)</label>
                    <input type="number" min="0" value={matchData.damage} onChange={e => setMatchData({...matchData, damage: parseInt(e.target.value) || 0})} className="w-full bg-slate-900 border border-slate-700 rounded-2xl p-4 text-slate-100 outline-none focus:border-emerald-500 transition-all" />
                  </div>
               </div>

               <div className="grid grid-cols-3 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest">Kills</label>
                    <input type="number" min="0" value={matchData.kills} onChange={e => setMatchData({...matchData, kills: parseInt(e.target.value) || 0})} className="w-full bg-slate-900 border border-emerald-500/20 rounded-2xl p-4 text-emerald-400 font-bold outline-none focus:border-emerald-500 transition-all" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-rose-500 uppercase tracking-widest">Deaths</label>
                    <input type="number" min="0" value={matchData.deaths} onChange={e => setMatchData({...matchData, deaths: parseInt(e.target.value) || 0})} className="w-full bg-slate-900 border border-rose-500/20 rounded-2xl p-4 text-rose-400 font-bold outline-none focus:border-rose-500 transition-all" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-sky-500 uppercase tracking-widest">Assists</label>
                    <input type="number" min="0" value={matchData.assists} onChange={e => setMatchData({...matchData, assists: parseInt(e.target.value) || 0})} className="w-full bg-slate-900 border border-sky-500/20 rounded-2xl p-4 text-sky-400 font-bold outline-none focus:border-sky-500 transition-all" />
                  </div>
               </div>

               <button type="submit" disabled={isSaving || !selectedPlayerId || !selectedSeasonId} className="w-full bg-blue-600 hover:bg-blue-500 py-6 rounded-2xl font-bold text-xl flex items-center justify-center gap-3 transition-all active:scale-95 shadow-xl shadow-blue-600/20 disabled:opacity-30 text-white">
                  {isSaving ? (
                    <div className="w-7 h-7 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
                  ) : (
                    <>
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v3m0 0v3m0-3h3m-3 0H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                      Adicionar ao Ranking Local
                    </>
                  )}
               </button>
            </form>

            <div className="mt-12 pt-8 border-t border-slate-700/50 flex flex-col gap-4">
              <button onClick={onResetData} className="w-full bg-rose-950/20 hover:bg-rose-950/40 text-rose-500 border border-rose-900/30 py-4 rounded-xl font-bold transition-all text-xs uppercase tracking-widest">Wipe (Resetar Tudo)</button>
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

import { Player, Season, PlayerStats } from '../types';

// ==================================================================================
// 🚨 ÁREA DE CONFIGURAÇÃO OBRIGATÓRIA PARA ACESSO PÚBLICO 🚨
// Para que o ranking apareça para todos SEM pedir senha, cole suas chaves abaixo.
// ==================================================================================
const HARDCODED_SUPABASE_URL = ""; 
const HARDCODED_SUPABASE_ANON_KEY = "";
// ==================================================================================

const getEnvVar = (key: string): string => {
  try {
    // Tenta pegar de variáveis de ambiente modernas (Vite)
    // @ts-ignore
    if (typeof import.meta !== 'undefined' && import.meta.env) {
      // @ts-ignore
      return import.meta.env[`VITE_${key}`] || import.meta.env[key] || '';
    }
  } catch (e) {}

  try {
    // Tenta pegar de variáveis de ambiente legadas (Process/Node)
    if (typeof process !== 'undefined' && process.env) {
      return process.env[key] || 
             process.env[`VITE_${key}`] || 
             process.env[`REACT_APP_${key}`] || 
             process.env[`NEXT_PUBLIC_${key}`] || '';
    }
  } catch (e) {}

  return '';
};

const getKeys = () => {
  // 1. Prioridade: Chaves coladas diretamente no código (para visitantes verem)
  if (HARDCODED_SUPABASE_URL && HARDCODED_SUPABASE_ANON_KEY) {
    return { url: HARDCODED_SUPABASE_URL, anonKey: HARDCODED_SUPABASE_ANON_KEY };
  }

  // 2. Prioridade: Variáveis de Ambiente (.env)
  const envUrl = getEnvVar('SUPABASE_URL');
  const envKey = getEnvVar('SUPABASE_ANON_KEY');
  if (envUrl && envKey) {
    return { url: envUrl, anonKey: envKey };
  }

  // 3. Prioridade: LocalStorage (Configurado via Painel Admin)
  const localUrl = localStorage.getItem('supabase_url');
  const localKey = localStorage.getItem('supabase_anon_key');
  if (localUrl && localKey) {
    return { url: localUrl, anonKey: localKey };
  }

  return { url: '', anonKey: '' };
};

async function supabaseFetch(table: string, method: 'GET' | 'POST' | 'DELETE' = 'GET', body?: any, query: string = '') {
  const { url: baseUrl, anonKey } = getKeys();

  if (!baseUrl || !anonKey) {
    console.warn(`[Supabase] Credenciais não encontradas para a tabela ${table}.`);
    return null;
  }

  // Remove barra final da URL se houver
  const cleanUrl = baseUrl.replace(/\/$/, "");

  // Para DELETE sem filtro específico (apagar tudo), precisamos garantir que a API aceite.
  // Muitas vezes o Supabase exige um filtro para DELETE. Usaremos 'id.neq.0' como "todos" se a query estiver vazia no DELETE.
  let safeQuery = query;
  if (method === 'DELETE' && (!query || query === '?select=*')) {
     safeQuery = '?id=neq.0'; // Hack para selecionar "todos" se IDs forem strings ou numeros != 0
  }

  const endpoint = `${cleanUrl}/rest/v1/${table}${safeQuery}`;

  const headers: HeadersInit = {
    'apikey': anonKey,
    'Authorization': `Bearer ${anonKey}`,
    'Content-Type': 'application/json',
    'Prefer': method === 'POST' ? 'return=representation' : '',
  };

  try {
    const response = await fetch(endpoint, {
      method,
      headers,
      body: body ? JSON.stringify(body) : undefined,
    });

    if (!response.ok) {
      const text = await response.text();
      console.error(`[Supabase Error] ${response.status} em ${table} (${method}):`, text);
      throw new Error(text);
    }

    if (method === 'DELETE') return true;

    try {
      const data = await response.json();
      return data || [];
    } catch (e) {
      return [];
    }

  } catch (err) {
    console.error(`[Network Error] Falha ao conectar em ${table}:`, err);
    throw err;
  }
}

export const db = {
  isCloudEnabled: () => {
    const { url, anonKey } = getKeys();
    return !!url && !!anonKey;
  },

  setCloudKeys: (url: string, key: string) => {
    localStorage.setItem('supabase_url', url.trim());
    localStorage.setItem('supabase_anon_key', key.trim());
  },

  clearCloudKeys: () => {
    localStorage.removeItem('supabase_url');
    localStorage.removeItem('supabase_anon_key');
  },

  async getPlayers(): Promise<Player[] | null> {
    try { return await supabaseFetch('players', 'GET', null, '?select=*'); } catch { return null; }
  },

  async getSeasons(): Promise<Season[] | null> {
    try { return await supabaseFetch('seasons', 'GET', null, '?select=*&order=id.desc'); } catch { return null; }
  },

  async getStats(): Promise<PlayerStats[] | null> {
    try { return await supabaseFetch('stats', 'GET', null, '?select=*'); } catch { return null; }
  },

  // Método unificado para salvar tudo na ordem correta
  async syncDatabase(players: Player[], seasons: Season[], stats: PlayerStats[]): Promise<void> {
    if (!this.isCloudEnabled()) return;

    try {
      console.log("Iniciando sincronização...");

      // 1. Apagar filhos primeiro (Stats dependem de Players e Seasons)
      await supabaseFetch('stats', 'DELETE');

      // 2. Apagar pais
      // Usamos Promise.all aqui pois players e seasons não dependem entre si
      await Promise.all([
        supabaseFetch('players', 'DELETE'),
        supabaseFetch('seasons', 'DELETE')
      ]);

      // 3. Criar pais
      if (players.length > 0) await supabaseFetch('players', 'POST', players);
      if (seasons.length > 0) await supabaseFetch('seasons', 'POST', seasons);

      // 4. Criar filhos
      if (stats.length > 0) await supabaseFetch('stats', 'POST', stats);

      console.log("Sincronização concluída com sucesso.");
    } catch (error) {
      console.error("Erro fatal na sincronização:", error);
      throw error; // Propaga erro para a UI avisar o usuário
    }
  },

  // Mantido apenas para limpar tudo explicitamente
  async clearDatabase(): Promise<void> {
    if (this.isCloudEnabled()) {
      await supabaseFetch('stats', 'DELETE');
      await supabaseFetch('players', 'DELETE');
      await supabaseFetch('seasons', 'DELETE');
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { ViewType, Player, Season, PlayerStats, FullRankingEntry } from './types';
import RankingTable from './components/RankingTable';
import AdminPanel from './components/AdminPanel';
import { db } from './services/databaseService';
import { getRankingInsights } from './services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const ADMIN_PASSWORD = "x5admin2024";

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('ranking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState<boolean>(() => {
    return sessionStorage.getItem('x5_is_admin') === 'true';
  });

  const [players, setPlayers] = useState<Player[]>([]);
  const [seasons, setSeasons] = useState<Season[]>([]);
  const [stats, setStats] = useState<PlayerStats[]>([]);

  const [isLoading, setIsLoading] = useState(true);
  const [selectedSeasonId, setSelectedSeasonId] = useState('');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loadingAi, setLoadingAi] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);

  // Busca dados automaticamente ao carregar
  const fetchData = async () => {
    setIsLoading(true);

    try {
      const [cloudPlayers, cloudSeasons, cloudStats] = await Promise.all([
        db.getPlayers(),
        db.getSeasons(),
        db.getStats()
      ]);

      if (cloudPlayers && cloudSeasons && cloudStats) {
        setPlayers(cloudPlayers || []);
        setSeasons(cloudSeasons || []);
        setStats(cloudStats || []);

        // Seleciona automaticamente a última temporada alimentada
        if (cloudSeasons && cloudSeasons.length > 0 && !selectedSeasonId) {
          setSelectedSeasonId(cloudSeasons[0].id);
        }
      }
    } catch (error) {
      console.error("Erro ao buscar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === ADMIN_PASSWORD) {
      setIsAdminAuthenticated(true);
      sessionStorage.setItem('x5_is_admin', 'true');
      setLoginError(false);
      setAdminPasswordInput('');
    } else {
      setLoginError(true);
    }
  };

  const handleResetData = async () => {
    if (window.confirm("ATENÇÃO: Isso apagará TODOS os dados do banco de dados na nuvem. Continuar?")) {
      setIsLoading(true);
      await db.clearDatabase();
      window.location.reload();
    }
  };

  const currentRanking: FullRankingEntry[] = useMemo(() => {
    if (!selectedSeasonId) return [];

    return stats
      .filter(s => s.seasonId === selectedSeasonId)
      .map(s => {
        const player = players.find(p => p.id === s.playerId);
        const kdValue = s.deaths === 0 ? s.kills : s.kills / s.deaths;
        return {
          ...s,
          nick: player?.nick || 'Desconhecido',
          kd: kdValue,
          damagePerMatch: s.matches === 0 ? 0 : s.damage / s.matches
        };
      })
      .sort((a, b) => b.kd - a.kd);
  }, [stats, selectedSeasonId, players]);

  // Admin Actions Handlers
  const handleAddPlayer = (nick: string) => setPlayers(prev => [...prev, { id: `p${Date.now()}`, nick }]);

  const handleDeletePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
    setStats(prev => prev.filter(s => s.playerId !== id));
  };

  const handleAddSeason = (name: string) => {
    const id = `s${Date.now()}`;
    setSeasons(prev => [{ id, name }, ...prev]); 
    if (!selectedSeasonId) setSelectedSeasonId(id);
  };

  const handleDeleteSeason = (id: string) => {
    setSeasons(prev => prev.filter(s => s.id !== id));
    setStats(prev => prev.filter(s => s.seasonId !== id));
    if(selectedSeasonId === id && seasons.length > 1) setSelectedSeasonId(seasons[1].id);
    else if(selectedSeasonId === id) setSelectedSeasonId('');
  };

  const handleUpdateStats = (entry: Omit<PlayerStats, 'id'>) => {
    setStats(prev => {
      const newStats = [...prev];
      const idx = newStats.findIndex(s => s.playerId === entry.playerId && s.seasonId === entry.seasonId);
      if (idx > -1) {
        newStats[idx] = { 
          ...newStats[idx], 
          matches: newStats[idx].matches + entry.matches,
          kills: newStats[idx].kills + entry.kills,
          deaths: newStats[idx].deaths + entry.deaths,
          assists: newStats[idx].assists + entry.assists,
          damage: newStats[idx].damage + entry.damage
        };
      } else {
        newStats.push({ ...entry, id: `st${Date.now()}` });
      }
      return newStats;
    });
  };

  const handlePublishToCloud = async () => {
    setIsLoading(true);
    try {
      // Usa o novo método sincronizado que evita erros de Foreign Key
      await db.syncDatabase(players, seasons, stats);
      alert("✅ Dados sincronizados com sucesso!");
    } catch (e: any) {
      console.error(e);
      alert(`❌ Falha ao publicar: ${e.message || "Erro desconhecido"}`);
    } finally {
      setIsLoading(false);
    }
  };

  const generateAICommentary = async () => {
    if (currentRanking.length === 0) return;
    setLoadingAi(true);
    const seasonName = seasons.find(s => s.id === selectedSeasonId)?.name || 'Temporada';
    const insight = await getRankingInsights(currentRanking, seasonName);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  if (isLoading && view === 'ranking' && players.length === 0) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center text-slate-400 font-gaming">
        <div className="w-12 h-12 border-2 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-sm tracking-widest uppercase opacity-50">Carregando X5 Ranking...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 bg-slate-900/90 backdrop-blur-md border-b border-slate-800 px-6 py-4 shadow-xl">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => { setView('ranking'); fetchData(); }}>
            <div className="w-10 h-10 bg-emerald-600 rounded-lg flex items-center justify-center font-gaming text-2xl font-bold italic shadow-lg shadow-emerald-500/20">X5</div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-gaming font-bold tracking-tight bg-gradient-to-r from-emerald-400 to-blue-400 bg-clip-text text-transparent">
                RANKING AMIGOS
              </h1>
              <span className="text-[9px] font-bold text-slate-500 uppercase tracking-tighter">
                Estatísticas em Tempo Real
              </span>
            </div>
          </div>

          <nav className="flex items-center gap-2 bg-slate-800 p-1 rounded-xl border border-slate-700">
            <button onClick={() => setView('ranking')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm ${view === 'ranking' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Ranking</button>
            <button onClick={() => setView('admin')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm ${view === 'admin' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Admin</button>
            <button onClick={fetchData} className="p-2 text-slate-500 hover:text-emerald-400" title="Atualizar Dados">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
            </button>
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {view === 'ranking' ? (
          <div className="space-y-8 animate-in fade-in duration-500">
             <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="w-full md:w-auto">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Selecione a Temporada</label>
                  <select 
                    value={selectedSeasonId} 
                    onChange={(e) => setSelectedSeasonId(e.target.value)} 
                    className="w-full md:w-72 bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-emerald-500 shadow-xl"
                  >
                    {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    {seasons.length === 0 && <option value="">Nenhuma temporada encontrada</option>}
                  </select>
                </div>
                <button onClick={generateAICommentary} disabled={loadingAi || currentRanking.length === 0} className="w-full md:w-auto flex items-center justify-center gap-2 bg-gradient-to-r from-emerald-600 to-blue-600 px-8 py-4 rounded-xl font-bold shadow-2xl transition-all disabled:opacity-50">
                  {loadingAi ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : "✨ Analisar com Gemini"}
                </button>
             </div>

             {aiInsight && (
               <div className="bg-slate-900 border border-emerald-500/20 p-6 rounded-2xl shadow-2xl animate-in slide-in-from-top-4">
                 <h3 className="text-emerald-400 font-bold mb-2">✨ Insight da IA</h3>
                 <div className="text-slate-300 italic whitespace-pre-wrap">{aiInsight}</div>
                 <button onClick={() => setAiInsight('')} className="mt-4 text-[10px] text-slate-500 uppercase hover:text-slate-300 underline">Fechar</button>
               </div>
             )}

             {currentRanking.length > 0 ? (
               <div className="space-y-10">
                 <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
                    <div className="lg:col-span-3 bg-slate-900/50 p-6 rounded-2xl border border-slate-800 h-[350px]">
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={currentRanking}>
                          <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                          <XAxis dataKey="nick" stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                          <YAxis stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                          <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '12px' }} />
                          <Bar dataKey="kd" radius={[6, 6, 0, 0]} barSize={40}>
                             {currentRanking.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.kd >= 1.5 ? '#10b981' : entry.kd >= 1.0 ? '#3b82f6' : '#f43f5e'} />)}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                   </div>
                   <div className="bg-slate-900 border border-slate-800 p-8 rounded-2xl flex flex-col justify-center items-center text-center shadow-xl">
                      <div className="mb-6">
                        <p className="text-slate-500 uppercase text-xs font-bold mb-1">Kills</p>
                        <p className="text-5xl font-gaming font-bold text-emerald-400">
                          {currentRanking.reduce((acc, curr) => acc + curr.kills, 0)}
                        </p>
                      </div>
                      <div className="w-full h-px bg-slate-800 my-4"></div>
                      <div>
                        <p className="text-slate-500 uppercase text-xs font-bold mb-1">Dano Total</p>
                        <p className="text-3xl font-gaming font-bold text-orange-400">
                          {(currentRanking.reduce((acc, curr) => acc + curr.damage, 0)).toLocaleString('pt-BR')}
                        </p>
                      </div>
                   </div>
                 </div>
                 <RankingTable data={currentRanking} />
               </div>
             ) : (
               <div className="text-center py-32 bg-slate-900/30 border border-slate-800 rounded-3xl border-dashed">
                 <p className="text-slate-500 text-lg italic">
                    {players.length === 0 ? 'Conectando ao banco de dados...' : 'Sem dados para esta temporada.'}
                 </p>
               </div>
             )}
          </div>
        ) : !isAdminAuthenticated ? (
          <div className="max-w-md mx-auto mt-20 p-10 bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl animate-in zoom-in-95">
            <h2 className="text-2xl font-gaming font-bold text-center mb-6 text-emerald-400">Autenticação Master</h2>
            <form onSubmit={handleAdminLogin} className="space-y-4">
              <input 
                type="password" 
                value={adminPasswordInput} 
                onChange={(e) => {setAdminPasswordInput(e.target.value); setLoginError(false);}} 
                placeholder="Senha de Acesso" 
                className={`w-full bg-slate-800 border ${loginError ? 'border-rose-500' : 'border-slate-700'} rounded-xl px-4 py-4 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-emerald-500 transition-all`}
                autoFocus 
              />
              <button type="submit" className="w-full bg-emerald-600 hover:bg-emerald-700 py-4 rounded-xl font-bold shadow-lg transition-all">Acessar Painel</button>
            </form>
          </div>
        ) : (
          <AdminPanel 
            players={players} seasons={seasons} stats={stats}
            onAddPlayer={handleAddPlayer} onDeletePlayer={handleDeletePlayer}
            onAddSeason={handleAddSeason} onDeleteSeason={handleDeleteSeason}
            onUpdateStats={handleUpdateStats} onResetData={handleResetData} onSetView={setView}
            onEditPlayer={() => {}} onEditSeason={() => {}}
            onPublish={handlePublishToCloud}
          />
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full bg-slate-900/80 backdrop-blur-md border-t border-slate-800/50 py-3 text-center z-40">
        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
          X5 Friends Ranking &bull; Dados em Nuvem
        </p>
      </footer>
    </div>
  );
};

export default App;

export interface Player {
  id: string;
  nick: string;
}

export interface Season {
  id: string;
  name: string;
}

export interface PlayerStats {
  id: string;
  playerId: string;
  seasonId: string;
  matches: number;
  kills: number;
  deaths: number;
  assists: number;
  damage: number;
}

export interface FullRankingEntry extends PlayerStats {
  nick: string;
  kd: number;
  damagePerMatch: number;
}

export type ViewType = 'ranking' | 'admin' | 'balancer';

import React, { useState, useMemo } from 'react';
import { Player, Season, PlayerStats, FullRankingEntry } from '../types';

interface TeamBalancerProps {
  players: Player[];
  seasons: Season[];
  stats: PlayerStats[];
}

interface TeamResult {
  teamA: FullRankingEntry[];
  teamB: FullRankingEntry[];
  avgA: number;
  avgB: number;
}

const TeamBalancer: React.FC<TeamBalancerProps> = ({ players, seasons, stats }) => {
  const [selectedSeasonId, setSelectedSeasonId] = useState<string>(seasons[0]?.id || '');
  const [selectedPlayerIds, setSelectedPlayerIds] = useState<string[]>([]);
  const [result, setResult] = useState<TeamResult | null>(null);

  // Calcula os stats atuais baseado na temporada selecionada (mesma lógica do Ranking)
  const playerPool: FullRankingEntry[] = useMemo(() => {
    if (!selectedSeasonId) return [];

    // Mapeia todos os jogadores, buscando seus stats na temporada ou zerando se não tiver
    return players.map(p => {
      const s = stats.find(st => st.playerId === p.id && st.seasonId === selectedSeasonId);
      const kills = s?.kills || 0;
      const deaths = s?.deaths || 0;
      const kd = deaths === 0 ? kills : kills / deaths;

      return {
        id: s?.id || `temp_${p.id}`,
        playerId: p.id,
        seasonId: selectedSeasonId,
        matches: s?.matches || 0,
        kills: kills,
        deaths: deaths,
        assists: s?.assists || 0,
        damage: s?.damage || 0,
        nick: p.nick,
        kd: kd,
        damagePerMatch: (s?.matches || 0) > 0 ? (s?.damage || 0) / (s?.matches || 1) : 0
      };
    }).sort((a, b) => a.nick.localeCompare(b.nick));
  }, [players, stats, selectedSeasonId]);

  const togglePlayer = (id: string) => {
    if (selectedPlayerIds.includes(id)) {
      setSelectedPlayerIds(prev => prev.filter(pId => pId !== id));
    } else {
      if (selectedPlayerIds.length < 10) {
        setSelectedPlayerIds(prev => [...prev, id]);
      }
    }
  };

  const generateTeams = () => {
    if (selectedPlayerIds.length !== 10) return;

    // 1. Pega os objetos completos dos jogadores selecionados
    const selectedPlayers = playerPool.filter(p => selectedPlayerIds.includes(p.playerId));

    // 2. Ordena por KD decrescente (do melhor para o pior)
    const sortedPlayers = [...selectedPlayers].sort((a, b) => b.kd - a.kd);

    const teamA: FullRankingEntry[] = [];
    const teamB: FullRankingEntry[] = [];
    let sumA = 0;
    let sumB = 0;

    // 3. Algoritmo Guloso (Greedy) para balanceamento
    // Itera do melhor para o pior, adicionando sempre ao time que tem a menor soma de KD atual
    sortedPlayers.forEach(player => {
      if (sumA <= sumB) {
        teamA.push(player);
        sumA += player.kd;
      } else {
        teamB.push(player);
        sumB += player.kd;
      }
    });

    setResult({
      teamA,
      teamB,
      avgA: sumA / 5,
      avgB: sumB / 5
    });
  };

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 pb-10">
      <div className="text-center mb-8">
        <h2 className="text-3xl font-gaming font-bold text-white mb-2">Sorteio Equilibrado</h2>
        <p className="text-slate-400">Selecione 10 jogadores para montar times balanceados pelo K/D da temporada.</p>
      </div>

      {/* SELEÇÃO DE TEMPORADA */}
      <div className="flex justify-center mb-8">
        <div className="w-full max-w-md">
           <label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Temporada Base (K/D)</label>
           <select 
             value={selectedSeasonId} 
             onChange={(e) => { setSelectedSeasonId(e.target.value); setResult(null); }} 
             className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-emerald-500 shadow-xl"
           >
             {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
           </select>
        </div>
      </div>

      {/* GRADE DE SELEÇÃO */}
      {!result && (
        <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800 mb-8">
          <div className="flex justify-between items-center mb-4">
            <h3 className="font-gaming text-xl text-emerald-400 font-bold">
              Selecionar Jogadores <span className="text-slate-500 ml-2 text-base">({selectedPlayerIds.length}/10)</span>
            </h3>
            {selectedPlayerIds.length > 0 && (
              <button onClick={() => setSelectedPlayerIds([])} className="text-xs text-rose-400 hover:text-rose-300 underline">Limpar Seleção</button>
            )}
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-3">
            {playerPool.map(player => {
              const isSelected = selectedPlayerIds.includes(player.playerId);
              return (
                <button
                  key={player.playerId}
                  onClick={() => togglePlayer(player.playerId)}
                  disabled={!isSelected && selectedPlayerIds.length >= 10}
                  className={`
                    relative p-3 rounded-xl border text-left transition-all group
                    ${isSelected 
                      ? 'bg-emerald-600 border-emerald-500 shadow-lg shadow-emerald-900/50 scale-105 z-10' 
                      : 'bg-slate-800 border-slate-700 hover:border-slate-500 hover:bg-slate-750'}
                    ${!isSelected && selectedPlayerIds.length >= 10 ? 'opacity-40 cursor-not-allowed' : ''}
                  `}
                >
                  <div className="flex justify-between items-start">
                    <span className={`font-bold truncate pr-2 ${isSelected ? 'text-white' : 'text-slate-300'}`}>{player.nick}</span>
                    <span className={`text-xs font-mono px-1.5 py-0.5 rounded ${isSelected ? 'bg-emerald-800 text-emerald-200' : 'bg-slate-900 text-slate-500'}`}>
                      {player.kd.toFixed(2)}
                    </span>
                  </div>
                </button>
              );
            })}
          </div>

          <div className="mt-8 flex justify-center">
            <button 
              onClick={generateTeams}
              disabled={selectedPlayerIds.length !== 10}
              className="bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white px-10 py-4 rounded-xl font-bold text-lg shadow-2xl transition-all disabled:opacity-50 disabled:cursor-not-allowed transform active:scale-95"
            >
              SORTEAR TIMES EQUILIBRADOS
            </button>
          </div>
        </div>
      )}

      {/* RESULTADO DOS TIMES */}
      {result && (
        <div className="space-y-8 animate-in zoom-in-95 duration-500">
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* TIME A */}
              <div className="bg-slate-900 border border-blue-500/30 rounded-3xl overflow-hidden shadow-2xl shadow-blue-900/20">
                <div className="bg-blue-600/20 p-4 border-b border-blue-500/30 flex justify-between items-center">
                  <h3 className="font-gaming text-2xl font-bold text-blue-400">TIME ALPHA</h3>
                  <div className="text-right">
                    <p className="text-[10px] uppercase text-blue-300 font-bold tracking-widest">Média KD</p>
                    <p className="text-xl font-mono font-bold text-white">{result.avgA.toFixed(2)}</p>
                  </div>
                </div>
                <div className="divide-y divide-slate-800">
                  {result.teamA.map(p => (
                    <div key={p.playerId} className="p-4 flex justify-between items-center hover:bg-blue-900/10 transition-colors">
                      <span className="font-bold text-slate-200">{p.nick}</span>
                      <span className="text-sm font-mono text-slate-500 bg-slate-950 px-2 py-1 rounded border border-slate-800">KD {p.kd.toFixed(2)}</span>
                    </div>
                  ))}
                </div>
              </div>

              {/* TIME B */}
              <div className="bg-slate-900 border border-rose-500/30 rounded-3xl overflow-hidden shadow-2xl shadow-rose-900/20">
                <div className="bg-rose-600/20 p-4 border-b border-rose-500/30 flex justify-between items-center">
                  <h3 className="font-gaming text-2xl font-bold text-rose-400">TIME OMEGA</h3>
                  <div className="text-right">
                    <p className="text-[10px] uppercase text-rose-300 font-bold tracking-widest">Média KD</p>
                    <p className="text-xl font-mono font-bold text-white">{result.avgB.toFixed(2)}</p>
                  </div>
                </div>
                <div className="divide-y divide-slate-800">
                  {result.teamB.map(p => (
                    <div key={p.playerId} className="p-4 flex justify-between items-center hover:bg-rose-900/10 transition-colors">
                      <span className="font-bold text-slate-200">{p.nick}</span>
                      <span className="text-sm font-mono text-slate-500 bg-slate-950 px-2 py-1 rounded border border-slate-800">KD {p.kd.toFixed(2)}</span>
                    </div>
                  ))}
                </div>
              </div>
           </div>

           <div className="flex justify-center mt-8 gap-4">
             <button onClick={generateTeams} className="bg-slate-800 hover:bg-slate-700 text-slate-200 px-6 py-3 rounded-xl font-bold border border-slate-700 transition-all">
               Re-sortear (Mesmos Jogadores)
             </button>
             <button onClick={() => setResult(null)} className="bg-emerald-600 hover:bg-emerald-500 text-white px-6 py-3 rounded-xl font-bold shadow-lg transition-all">
               Novo Sorteio
             </button>
           </div>
        </div>
      )}
    </div>
  );
};

export default TeamBalancer;

import React, { useState, useEffect, useMemo } from 'react';
import { ViewType, Player, Season, PlayerStats, FullRankingEntry } from './types';
import RankingTable from './components/RankingTable';
import AdminPanel from './components/AdminPanel';
import TeamBalancer from './components/TeamBalancer';
import { db } from './services/databaseService';
import { getRankingInsights } from './services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const ADMIN_PASSWORD = "x5admin2024";

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('ranking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState<boolean>(() => {
    return sessionStorage.getItem('x5_is_admin') === 'true';
  });

  const [players, setPlayers] = useState<Player[]>([]);
  const [seasons, setSeasons] = useState<Season[]>([]);
  const [stats, setStats] = useState<PlayerStats[]>([]);

  const [isLoading, setIsLoading] = useState(true);
  const [selectedSeasonId, setSelectedSeasonId] = useState('');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loadingAi, setLoadingAi] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);

  // Busca dados automaticamente ao carregar
  const fetchData = async () => {
    setIsLoading(true);

    try {
      const [cloudPlayers, cloudSeasons, cloudStats] = await Promise.all([
        db.getPlayers(),
        db.getSeasons(),
        db.getStats()
      ]);

      if (cloudPlayers && cloudSeasons && cloudStats) {
        setPlayers(cloudPlayers || []);
        setSeasons(cloudSeasons || []);
        setStats(cloudStats || []);

        // Seleciona automaticamente a última temporada alimentada
        if (cloudSeasons && cloudSeasons.length > 0 && !selectedSeasonId) {
          setSelectedSeasonId(cloudSeasons[0].id);
        }
      }
    } catch (error) {
      console.error("Erro ao buscar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === ADMIN_PASSWORD) {
      setIsAdminAuthenticated(true);
      sessionStorage.setItem('x5_is_admin', 'true');
      setLoginError(false);
      setAdminPasswordInput('');
    } else {
      setLoginError(true);
    }
  };

  const handleResetData = async () => {
    if (window.confirm("ATENÇÃO: Isso apagará TODOS os dados do banco de dados na nuvem. Continuar?")) {
      setIsLoading(true);
      await db.clearDatabase();
      window.location.reload();
    }
  };

  const currentRanking: FullRankingEntry[] = useMemo(() => {
    if (!selectedSeasonId) return [];

    return stats
      .filter(s => s.seasonId === selectedSeasonId)
      .map(s => {
        const player = players.find(p => p.id === s.playerId);
        const kdValue = s.deaths === 0 ? s.kills : s.kills / s.deaths;
        return {
          ...s,
          nick: player?.nick || 'Desconhecido',
          kd: kdValue,
          damagePerMatch: s.matches === 0 ? 0 : s.damage / s.matches
        };
      })
      .sort((a, b) => b.kd - a.kd);
  }, [stats, selectedSeasonId, players]);

  // Admin Actions Handlers
  const handleAddPlayer = (nick: string) => setPlayers(prev => [...prev, { id: `p${Date.now()}`, nick }]);

  const handleDeletePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
    setStats(prev => prev.filter(s => s.playerId !== id));
  };

  const handleAddSeason = (name: string) => {
    const id = `s${Date.now()}`;
    setSeasons(prev => [{ id, name }, ...prev]); 
    if (!selectedSeasonId) setSelectedSeasonId(id);
  };

  const handleDeleteSeason = (id: string) => {
    setSeasons(prev => prev.filter(s => s.id !== id));
    setStats(prev => prev.filter(s => s.seasonId !== id));
    if(selectedSeasonId === id && seasons.length > 1) setSelectedSeasonId(seasons[1].id);
    else if(selectedSeasonId === id) setSelectedSeasonId('');
  };

  const handleUpdateStats = (entry: Omit<PlayerStats, 'id'>) => {
    setStats(prev => {
      const newStats = [...prev];
      const idx = newStats.findIndex(s => s.playerId === entry.playerId && s.seasonId === entry.seasonId);
      if (idx > -1) {
        newStats[idx] = { 
          ...newStats[idx], 
          matches: newStats[idx].matches + entry.matches,
          kills: newStats[idx].kills + entry.kills,
          deaths: newStats[idx].deaths + entry.deaths,
          assists: newStats[idx].assists + entry.assists,
          damage: newStats[idx].damage + entry.damage
        };
      } else {
        newStats.push({ ...entry, id: `st${Date.now()}` });
      }
      return newStats;
    });
  };

  const handlePublishToCloud = async () => {
    setIsLoading(true);
    try {
      // Usa o novo método sincronizado que evita erros de Foreign Key
      await db.syncDatabase(players, seasons, stats);
      alert("✅ Dados sincronizados com sucesso!");
    } catch (e: any) {
      console.error(e);
      alert(`❌ Falha ao publicar: ${e.message || "Erro desconhecido"}`);
    } finally {
      setIsLoading(false);
    }
  };

  const generateAICommentary = async () => {
    if (currentRanking.length === 0) return;
    setLoadingAi(true);
    const seasonName = seasons.find(s => s.id === selectedSeasonId)?.name || 'Temporada';
    const insight = await getRankingInsights(currentRanking, seasonName);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  if (isLoading && view === 'ranking' && players.length === 0) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center text-slate-400 font-gaming">
        <div className="w-12 h-12 border-2 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-sm tracking-widest uppercase opacity-50">Carregando X5 Ranking...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 bg-slate-900/90 backdrop-blur-md border-b border-slate-800 px-6 py-4 shadow-xl">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => { setView('ranking'); fetchData(); }}>
            <div className="w-10 h-10 bg-emerald-600 rounded-lg flex items-center justify-center font-gaming text-2xl font-bold italic shadow-lg shadow-emerald-500/20">X5</div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-gaming font-bold tracking-tight bg-gradient-to-r from-emerald-400 to-blue-400 bg-clip-text text-transparent">
                RANKING AMIGOS
              </h1>
              <span className="text-[9px] font-bold text-slate-500 uppercase tracking-tighter">
                Estatísticas em Tempo Real
              </span>
            </div>
          </div>

          <nav className="flex items-center gap-2 bg-slate-800 p-1 rounded-xl border border-slate-700 overflow-x-auto">
            <button onClick={() => setView('ranking')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm whitespace-nowrap ${view === 'ranking' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Ranking</button>
            <button onClick={() => setView('balancer')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm whitespace-nowrap ${view === 'balancer' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Sorteio Teams</button>
            <button onClick={() => setView('admin')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm whitespace-nowrap ${view === 'admin' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Admin</button>
            <button onClick={fetchData} className="p-2 text-slate-500 hover:text-emerald-400" title="Atualizar Dados">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
            </button>
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {view === 'ranking' ? (
          <div className="space-y-8 animate-in fade-in duration-500">
             <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="w-full md:w-auto">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Selecione a Temporada</label>
                  <select 
                    value={selectedSeasonId} 
                    onChange={(e) => setSelectedSeasonId(e.target.value)} 
                    className="w-full md:w-72 bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-emerald-500 shadow-xl"
                  >
                    {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    {seasons.length === 0 && <option value="">Nenhuma temporada encontrada</option>}
                  </select>
                </div>
                <button onClick={generateAICommentary} disabled={loadingAi || currentRanking.length === 0} className="w-full md:w-auto flex items-center justify-center gap-2 bg-gradient-to-r from-emerald-600 to-blue-600 px-8 py-4 rounded-xl font-bold shadow-2xl transition-all disabled:opacity-50">
                  {loadingAi ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : "✨ Analisar com Gemini"}
                </button>
             </div>

             {aiInsight && (
               <div className="bg-slate-900 border border-emerald-500/20 p-6 rounded-2xl shadow-2xl animate-in slide-in-from-top-4">
                 <h3 className="text-emerald-400 font-bold mb-2">✨ Insight da IA</h3>
                 <div className="text-slate-300 italic whitespace-pre-wrap">{aiInsight}</div>
                 <button onClick={() => setAiInsight('')} className="mt-4 text-[10px] text-slate-500 uppercase hover:text-slate-300 underline">Fechar</button>
               </div>
             )}

             {currentRanking.length > 0 ? (
               <div className="space-y-10">
                 <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
                    <div className="lg:col-span-3 bg-slate-900/50 p-6 rounded-2xl border border-slate-800 h-[350px]">
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={currentRanking}>
                          <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                          <XAxis dataKey="nick" stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                          <YAxis stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                          <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '12px' }} />
                          <Bar dataKey="kd" radius={[6, 6, 0, 0]} barSize={40}>
                             {currentRanking.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.kd >= 1.5 ? '#10b981' : entry.kd >= 1.0 ? '#3b82f6' : '#f43f5e'} />)}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                   </div>
                   <div className="bg-slate-900 border border-slate-800 p-8 rounded-2xl flex flex-col justify-center items-center text-center shadow-xl">
                      <div className="mb-6">
                        <p className="text-slate-500 uppercase text-xs font-bold mb-1">Kills</p>
                        <p className="text-5xl font-gaming font-bold text-emerald-400">
                          {currentRanking.reduce((acc, curr) => acc + curr.kills, 0)}
                        </p>
                      </div>
                      <div className="w-full h-px bg-slate-800 my-4"></div>
                      <div>
                        <p className="text-slate-500 uppercase text-xs font-bold mb-1">Dano Total</p>
                        <p className="text-3xl font-gaming font-bold text-orange-400">
                          {(currentRanking.reduce((acc, curr) => acc + curr.damage, 0)).toLocaleString('pt-BR')}
                        </p>
                      </div>
                   </div>
                 </div>
                 <RankingTable data={currentRanking} />
               </div>
             ) : (
               <div className="text-center py-32 bg-slate-900/30 border border-slate-800 rounded-3xl border-dashed">
                 <p className="text-slate-500 text-lg italic">
                    {players.length === 0 ? 'Conectando ao banco de dados...' : 'Sem dados para esta temporada.'}
                 </p>
               </div>
             )}
          </div>
        ) : view === 'balancer' ? (
          <TeamBalancer players={players} seasons={seasons} stats={stats} />
        ) : !isAdminAuthenticated ? (
          <div className="max-w-md mx-auto mt-20 p-10 bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl animate-in zoom-in-95">
            <h2 className="text-2xl font-gaming font-bold text-center mb-6 text-emerald-400">Autenticação Master</h2>
            <form onSubmit={handleAdminLogin} className="space-y-4">
              <input 
                type="password" 
                value={adminPasswordInput} 
                onChange={(e) => {setAdminPasswordInput(e.target.value); setLoginError(false);}} 
                placeholder="Senha de Acesso" 
                className={`w-full bg-slate-800 border ${loginError ? 'border-rose-500' : 'border-slate-700'} rounded-xl px-4 py-4 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-emerald-500 transition-all`}
                autoFocus 
              />
              <button type="submit" className="w-full bg-emerald-600 hover:bg-emerald-700 py-4 rounded-xl font-bold shadow-lg transition-all">Acessar Painel</button>
            </form>
          </div>
        ) : (
          <AdminPanel 
            players={players} seasons={seasons} stats={stats}
            onAddPlayer={handleAddPlayer} onDeletePlayer={handleDeletePlayer}
            onAddSeason={handleAddSeason} onDeleteSeason={handleDeleteSeason}
            onUpdateStats={handleUpdateStats} onResetData={handleResetData} onSetView={setView}
            onEditPlayer={() => {}} onEditSeason={() => {}}
            onPublish={handlePublishToCloud}
          />
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full bg-slate-900/80 backdrop-blur-md border-t border-slate-800/50 py-3 text-center z-40">
        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
          X5 Friends Ranking &bull; Dados em Nuvem
        </p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { FullRankingEntry } from '../types';

interface RankingTableProps {
  data: FullRankingEntry[];
}

type SortKey = keyof FullRankingEntry;
type SortDirection = 'asc' | 'desc';

interface SortConfig {
  key: SortKey;
  direction: SortDirection;
}

const RankingTable: React.FC<RankingTableProps> = ({ data }) => {
  // Estado padrão: Ordenado por KD descendente (maior para o menor)
  const [sortConfig, setSortConfig] = useState<SortConfig>({
    key: 'kd',
    direction: 'desc',
  });

  const handleSort = (key: SortKey) => {
    setSortConfig((current) => ({
      key,
      direction: current.key === key && current.direction === 'desc' ? 'asc' : 'desc',
    }));
  };

  const sortedData = useMemo(() => {
    const sorted = [...data];
    return sorted.sort((a, b) => {
      const aValue = a[sortConfig.key];
      const bValue = b[sortConfig.key];

      if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
  }, [data, sortConfig]);

  const SortIcon = ({ columnKey }: { columnKey: SortKey }) => {
    const isActive = sortConfig.key === columnKey;

    return (
      <span className={`ml-2 inline-flex flex-col h-3 w-3 justify-center items-center transition-opacity ${isActive ? 'opacity-100' : 'opacity-20 group-hover:opacity-50'}`}>
        {/* Seta para cima */}
        <svg 
          className={`w-2 h-2 -mb-[2px] ${isActive && sortConfig.direction === 'asc' ? 'text-emerald-400' : 'text-slate-400'}`} 
          fill="currentColor" viewBox="0 0 24 24"
        >
          <path d="M12 4l-8 8h16l-8-8z" />
        </svg>
        {/* Seta para baixo */}
        <svg 
          className={`w-2 h-2 -mt-[2px] ${isActive && sortConfig.direction === 'desc' ? 'text-emerald-400' : 'text-slate-400'}`} 
          fill="currentColor" viewBox="0 0 24 24"
        >
          <path d="M12 20l8-8H4l8 8z" />
        </svg>
      </span>
    );
  };

  const renderHeader = (label: string, key: SortKey, colorClass: string = "text-slate-300", align: string = "text-left", title?: string) => (
    <th 
      className={`px-6 py-4 cursor-pointer group select-none transition-colors hover:bg-slate-800/50 ${colorClass} ${align}`}
      onClick={() => handleSort(key)}
      title={title}
    >
      <div className={`flex items-center ${align === "text-center" ? "justify-center" : "justify-start"}`}>
        {label}
        <SortIcon columnKey={key} />
      </div>
    </th>
  );

  return (
    <div className="overflow-x-auto rounded-xl border border-slate-700 bg-slate-800/50 backdrop-blur-sm shadow-2xl">
      <table className="w-full text-left border-collapse">
        <thead className="bg-slate-900/80 font-gaming uppercase tracking-wider text-sm">
          <tr>
            <th className="px-6 py-4 text-slate-500 w-16">#</th>
            {renderHeader("Nick", "nick", "text-slate-300")}
            {renderHeader("Partidas", "matches", "text-slate-300")}
            {renderHeader("Vítimas", "kills", "text-emerald-400")}
            {renderHeader("Mortes", "deaths", "text-rose-400")}
            {renderHeader("Assists", "assists", "text-sky-400")}
            {renderHeader("Dano", "damage", "text-orange-400")}
            {renderHeader("K/D", "kd", "text-yellow-400", "text-left", "Cálculo: Vítimas / Mortes")}
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-700">
          {sortedData.length === 0 ? (
            <tr>
              <td colSpan={8} className="px-6 py-10 text-center text-slate-500 italic">
                Nenhum dado encontrado para esta temporada.
              </td>
            </tr>
          ) : (
            sortedData.map((player, index) => (
              <tr 
                key={player.id} 
                className="hover:bg-slate-700/50 transition-colors group cursor-default"
              >
                <td className="px-6 py-4 font-gaming text-lg">
                  <span className={`
                    w-8 h-8 flex items-center justify-center rounded-full text-sm
                    ${index === 0 && sortConfig.key === 'kd' && sortConfig.direction === 'desc' ? 'bg-yellow-500/20 text-yellow-400 ring-1 ring-yellow-500' : ''}
                    ${index === 1 && sortConfig.key === 'kd' && sortConfig.direction === 'desc' ? 'bg-slate-400/20 text-slate-300 ring-1 ring-slate-400' : ''}
                    ${index === 2 && sortConfig.key === 'kd' && sortConfig.direction === 'desc' ? 'bg-orange-700/20 text-orange-400 ring-1 ring-orange-700' : ''}
                    ${(index > 2 || sortConfig.key !== 'kd' || sortConfig.direction !== 'desc') ? 'text-slate-500' : ''}
                  `}>
                    {index + 1}
                  </span>
                </td>
                <td className="px-6 py-4 font-bold text-slate-100 group-hover:text-blue-400 transition-colors">
                  {player.nick}
                </td>
                <td className="px-6 py-4 text-slate-300">{player.matches}</td>
                <td className="px-6 py-4 text-emerald-400 font-medium">{player.kills}</td>
                <td className="px-6 py-4 text-rose-400 font-medium">{player.deaths}</td>
                <td className="px-6 py-4 text-sky-400">{player.assists}</td>
                <td className="px-6 py-4 text-orange-400 font-medium">
                  {player.damage.toLocaleString('pt-BR')}
                </td>
                <td className="px-6 py-4">
                  <span className={`
                    px-2 py-1 rounded font-bold
                    ${player.kd >= 1.5 ? 'bg-emerald-500/20 text-emerald-400' : 
                      player.kd >= 1.0 ? 'bg-blue-500/20 text-blue-400' : 
                      'bg-rose-500/20 text-rose-400'}
                  `}>
                    {player.kd.toFixed(2)}
                  </span>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
};

export default RankingTable;

