              <h3 className={`text-xl font-gaming font-bold flex items-center gap-3 ${formMode === 'edit' ? 'text-amber-400' : 'text-emerald-400'}`}>
                <span className={`w-1.5 h-8 rounded-full ${formMode === 'edit' ? 'bg-amber-500' : 'bg-emerald-500'}`}></span>
                {formMode === 'edit' ? 'Editar Estatísticas' : 'Registrar Pontuação'}
              </h3>

              <div className="flex bg-slate-900 p-1 rounded-lg border border-slate-700">
                <button 
                  onClick={() => setFormMode('add')} 
                  className={`px-3 py-1.5 rounded text-xs font-bold transition-all ${formMode === 'add' ? 'bg-slate-700 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  SOMAR
                </button>
                <button 
                  onClick={() => setFormMode('edit')} 
                  className={`px-3 py-1.5 rounded text-xs font-bold transition-all ${formMode === 'edit' ? 'bg-amber-600 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  EDITAR
                </button>
              </div>
            </div>

            {formMode === 'edit' && (
              <div className="mb-6 bg-amber-500/10 border border-amber-500/20 p-4 rounded-xl">
                <p className="text-amber-200 text-xs font-bold">⚠️ Modo de Edição Ativo</p>
                <p className="text-amber-400/70 text-[10px] mt-1">Os valores abaixo substituirão o total atual. Use para corrigir erros.</p>
              </div>
            )}

            <form onSubmit={handleSubmitStats} className="space-y-8">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Atleta</label>
                    <select value={selectedPlayerId} onChange={(e) => setSelectedPlayerId(e.target.value)} required className="w-full bg-slate-900 border border-slate-700 rounded-2xl p-4 outline-none focus:border-emerald-500 transition-all text-slate-200 appearance-none cursor-pointer shadow-inner">
                      <option value="">Selecione o Jogador</option>
                      {players.map(p => <option key={p.id} value={p.id}>{p.nick}</option>)}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Temporada</label>
                    <select value={selectedSeasonId} onChange={(e) => setSelectedSeasonId(e.target.value)} required className="w-full bg-slate-900 border border-slate-700 rounded-2xl p-4 outline-none focus:border-emerald-500 transition-all text-slate-200 appearance-none cursor-pointer shadow-inner">
                      <option value="">Selecione a Temporada</option>
                      {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    </select>
                  </div>
               </div>

               <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{formMode === 'add' ? 'Partidas (+)' : 'Total Partidas'}</label>
                    <input type="number" min="0" value={matchData.matches} onChange={e => setMatchData({...matchData, matches: parseInt(e.target.value) || 0})} className="w-full bg-slate-900 border border-slate-700 rounded-2xl p-4 text-slate-100 outline-none focus:border-emerald-500 transition-all" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{formMode === 'add' ? 'Dano (+)' : 'Total Dano'}</label>
                    <input type="number" min="0" value={matchData.damage} onChange={e => setMatchData({...matchData, damage: parseInt(e.target.value) || 0})} className="w-full bg-slate-900 border border-slate-700 rounded-2xl p-4 text-slate-100 outline-none focus:border-emerald-500 transition-all" />
                  </div>
               </div>

               <div className="grid grid-cols-3 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest">{formMode === 'add' ? 'Kills (+)' : 'Total Kills'}</label>
                    <input type="number" min="0" value={matchData.kills} onChange={e => setMatchData({...matchData, kills: parseInt(e.target.value) || 0})} className="w-full bg-slate-900 border border-emerald-500/20 rounded-2xl p-4 text-emerald-400 font-bold outline-none focus:border-emerald-500 transition-all" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-rose-500 uppercase tracking-widest">{formMode === 'add' ? 'Deaths (+)' : 'Total Deaths'}</label>
                    <input type="number" min="0" value={matchData.deaths} onChange={e => setMatchData({...matchData, deaths: parseInt(e.target.value) || 0})} className="w-full bg-slate-900 border border-rose-500/20 rounded-2xl p-4 text-rose-400 font-bold outline-none focus:border-rose-500 transition-all" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-sky-500 uppercase tracking-widest">{formMode === 'add' ? 'Assists (+)' : 'Total Assists'}</label>
                    <input type="number" min="0" value={matchData.assists} onChange={e => setMatchData({...matchData, assists: parseInt(e.target.value) || 0})} className="w-full bg-slate-900 border border-sky-500/20 rounded-2xl p-4 text-sky-400 font-bold outline-none focus:border-sky-500 transition-all" />
                  </div>
               </div>

               <button 
                type="submit" 
                disabled={isSaving || !selectedPlayerId || !selectedSeasonId} 
                className={`w-full py-6 rounded-2xl font-bold text-xl flex items-center justify-center gap-3 transition-all active:scale-95 shadow-xl disabled:opacity-30 text-white
                  ${formMode === 'add' ? 'bg-blue-600 hover:bg-blue-500 shadow-blue-600/20' : 'bg-amber-600 hover:bg-amber-500 shadow-amber-600/20'}
                `}
               >
                  {isSaving ? (
                    <div className="w-7 h-7 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
                  ) : (
                    <>
                      {formMode === 'add' ? (
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v3m0 0v3m0-3h3m-3 0H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                      ) : (
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                      )}
                      {formMode === 'add' ? 'Adicionar ao Ranking Local' : 'Salvar Correção'}
                    </>
                  )}
               </button>
            </form>

            {isMaster && (
              <div className="mt-12 pt-8 border-t border-slate-700/50 flex flex-col gap-4">
                <button onClick={onResetData} className="w-full bg-rose-950/20 hover:bg-rose-950/40 text-rose-500 border border-rose-900/30 py-4 rounded-xl font-bold transition-all text-xs uppercase tracking-widest">Wipe (Resetar Tudo)</button>
              </div>
            )}
          </section>
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { ViewType, Player, Season, PlayerStats, FullRankingEntry, UserRole } from './types';
import RankingTable from './components/RankingTable';
import AdminPanel from './components/AdminPanel';
import TeamBalancer from './components/TeamBalancer';
import { db } from './services/databaseService';
import { getRankingInsights } from './services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

// Configuração de Senhas e Níveis
const AUTH_CONFIG = {
  MASTER_PASSWORD: "x5root2025",  // NOVA Senha Master (Permissão Total + Configs)
  EDITOR_PASSWORD: "x5admin2024"  // ANTIGA Senha Master -> Agora Editor (Apenas Stats/Add Player)
};

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('ranking');

  // Estado de Autenticação com Role
  const [userRole, setUserRole] = useState<UserRole>(() => {
    return (sessionStorage.getItem('x5_user_role') as UserRole) || null;
  });

  const [players, setPlayers] = useState<Player[]>([]);
  const [seasons, setSeasons] = useState<Season[]>([]);
  const [stats, setStats] = useState<PlayerStats[]>([]);

  const [isLoading, setIsLoading] = useState(true);
  const [selectedSeasonId, setSelectedSeasonId] = useState('');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loadingAi, setLoadingAi] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);

  // Busca dados automaticamente ao carregar
  const fetchData = async () => {
    setIsLoading(true);

    try {
      const [cloudPlayers, cloudSeasons, cloudStats] = await Promise.all([
        db.getPlayers(),
        db.getSeasons(),
        db.getStats()
      ]);

      if (cloudPlayers && cloudSeasons && cloudStats) {
        setPlayers(cloudPlayers || []);
        setSeasons(cloudSeasons || []);
        setStats(cloudStats || []);

        // Seleciona automaticamente a última temporada alimentada
        if (cloudSeasons && cloudSeasons.length > 0 && !selectedSeasonId) {
          setSelectedSeasonId(cloudSeasons[0].id);
        }
      }
    } catch (error) {
      console.error("Erro ao buscar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();

    if (adminPasswordInput === AUTH_CONFIG.MASTER_PASSWORD) {
      setUserRole('master');
      sessionStorage.setItem('x5_user_role', 'master');
      setLoginError(false);
      setAdminPasswordInput('');
    } else if (adminPasswordInput === AUTH_CONFIG.EDITOR_PASSWORD) {
      setUserRole('editor');
      sessionStorage.setItem('x5_user_role', 'editor');
      setLoginError(false);
      setAdminPasswordInput('');
    } else {
      setLoginError(true);
      setUserRole(null);
    }
  };

  const handleLogout = () => {
    setUserRole(null);
    sessionStorage.removeItem('x5_user_role');
    setView('ranking');
  };

  const handleResetData = async () => {
    if (window.confirm("ATENÇÃO: Isso apagará TODOS os dados do banco de dados na nuvem. Continuar?")) {
      setIsLoading(true);
      await db.clearDatabase();
      window.location.reload();
    }
  };

  const currentRanking: FullRankingEntry[] = useMemo(() => {
    if (!selectedSeasonId) return [];

    return stats
      .filter(s => s.seasonId === selectedSeasonId)
      .map(s => {
        const player = players.find(p => p.id === s.playerId);
        const kdValue = s.deaths === 0 ? s.kills : s.kills / s.deaths;
        return {
          ...s,
          nick: player?.nick || 'Desconhecido',
          kd: kdValue,
          damagePerMatch: s.matches === 0 ? 0 : s.damage / s.matches
        };
      })
      .sort((a, b) => b.kd - a.kd);
  }, [stats, selectedSeasonId, players]);

  // Filtra dados para o gráfico (apenas jogadores com 3+ partidas)
  const chartData = useMemo(() => {
    return currentRanking.filter(p => p.matches >= 3);
  }, [currentRanking]);

  // Admin Actions Handlers
  const handleAddPlayer = (nick: string) => setPlayers(prev => [...prev, { id: `p${Date.now()}`, nick }]);

  const handleEditPlayer = (id: string, newNick: string) => {
    setPlayers(prev => prev.map(p => p.id === id ? { ...p, nick: newNick } : p));
  };

  const handleDeletePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
    setStats(prev => prev.filter(s => s.playerId !== id));
  };

  const handleAddSeason = (name: string) => {
    const id = `s${Date.now()}`;
    setSeasons(prev => [{ id, name }, ...prev]); 
    if (!selectedSeasonId) setSelectedSeasonId(id);
  };

  const handleDeleteSeason = (id: string) => {
    setSeasons(prev => prev.filter(s => s.id !== id));
    setStats(prev => prev.filter(s => s.seasonId !== id));
    if(selectedSeasonId === id && seasons.length > 1) setSelectedSeasonId(seasons[1].id);
    else if(selectedSeasonId === id) setSelectedSeasonId('');
  };

  const handleUpdateStats = (entry: Omit<PlayerStats, 'id'>) => {
    setStats(prev => {
      const newStats = [...prev];
      const idx = newStats.findIndex(s => s.playerId === entry.playerId && s.seasonId === entry.seasonId);
      if (idx > -1) {
        newStats[idx] = { 
          ...newStats[idx], 
          matches: newStats[idx].matches + entry.matches,
          kills: newStats[idx].kills + entry.kills,
          deaths: newStats[idx].deaths + entry.deaths,
          assists: newStats[idx].assists + entry.assists,
          damage: newStats[idx].damage + entry.damage
        };
      } else {
        newStats.push({ ...entry, id: `st${Date.now()}` });
      }
      return newStats;
    });
  };

  const handleOverwriteStats = (entry: Omit<PlayerStats, 'id'>) => {
    setStats(prev => {
      const newStats = [...prev];
      const idx = newStats.findIndex(s => s.playerId === entry.playerId && s.seasonId === entry.seasonId);
      if (idx > -1) {
        newStats[idx] = { 
          ...newStats[idx], 
          matches: entry.matches,
          kills: entry.kills,
          deaths: entry.deaths,
          assists: entry.assists,
          damage: entry.damage
        };
      } else {
        newStats.push({ ...entry, id: `st${Date.now()}` });
      }
      return newStats;
    });
  };

  const handlePublishToCloud = async () => {
    setIsLoading(true);
    try {
      await db.syncDatabase(players, seasons, stats);
      alert("✅ Dados sincronizados com sucesso!");
    } catch (e: any) {
      console.error(e);
      alert(`❌ Falha ao publicar: ${e.message || "Erro desconhecido"}`);
    } finally {
      setIsLoading(false);
    }
  };

  const generateAICommentary = async () => {
    if (currentRanking.length === 0) return;
    setLoadingAi(true);
    const seasonName = seasons.find(s => s.id === selectedSeasonId)?.name || 'Temporada';
    const insight = await getRankingInsights(currentRanking, seasonName);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  if (isLoading && view === 'ranking' && players.length === 0) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center text-slate-400 font-gaming">
        <div className="w-12 h-12 border-2 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-sm tracking-widest uppercase opacity-50">Carregando X5 Ranking...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 bg-slate-900/90 backdrop-blur-md border-b border-slate-800 px-6 py-4 shadow-xl">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => { setView('ranking'); fetchData(); }}>
            <div className="w-10 h-10 bg-emerald-600 rounded-lg flex items-center justify-center font-gaming text-2xl font-bold italic shadow-lg shadow-emerald-500/20">X5</div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-gaming font-bold tracking-tight bg-gradient-to-r from-emerald-400 to-blue-400 bg-clip-text text-transparent">
                RANKING AMIGOS
              </h1>
              <span className="text-[9px] font-bold text-slate-500 uppercase tracking-tighter">
                Estatísticas em Tempo Real
              </span>
            </div>
          </div>

          <nav className="flex items-center gap-2 bg-slate-800 p-1 rounded-xl border border-slate-700 overflow-x-auto">
            <button onClick={() => setView('ranking')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm whitespace-nowrap ${view === 'ranking' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Ranking</button>
            <button onClick={() => setView('balancer')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm whitespace-nowrap ${view === 'balancer' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Sorteio Teams</button>
            <button onClick={() => setView('admin')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm whitespace-nowrap ${view === 'admin' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Admin</button>
            {userRole && (
               <button onClick={handleLogout} className="px-3 py-2 text-rose-400 hover:text-rose-300 hover:bg-rose-950/30 rounded-lg font-bold text-xs" title="Sair do modo Admin">
                 SAIR
               </button>
            )}
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {view === 'ranking' ? (
          <div className="space-y-8 animate-in fade-in duration-500">
             <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="w-full md:w-auto">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Selecione a Temporada</label>
                  <select 
                    value={selectedSeasonId} 
                    onChange={(e) => setSelectedSeasonId(e.target.value)} 
                    className="w-full md:w-72 bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-emerald-500 shadow-xl"
                  >
                    {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    {seasons.length === 0 && <option value="">Nenhuma temporada encontrada</option>}
                  </select>
                </div>
                <button onClick={generateAICommentary} disabled={loadingAi || currentRanking.length === 0} className="w-full md:w-auto flex items-center justify-center gap-2 bg-gradient-to-r from-emerald-600 to-blue-600 px-8 py-4 rounded-xl font-bold shadow-2xl transition-all disabled:opacity-50">
                  {loadingAi ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : "✨ Analisar com Gemini"}
                </button>
             </div>

             {aiInsight && (
               <div className="bg-slate-900 border border-emerald-500/20 p-6 rounded-2xl shadow-2xl animate-in slide-in-from-top-4">
                 <h3 className="text-emerald-400 font-bold mb-2">✨ Insight da IA</h3>
                 <div className="text-slate-300 italic whitespace-pre-wrap">{aiInsight}</div>
                 <button onClick={() => setAiInsight('')} className="mt-4 text-[10px] text-slate-500 uppercase hover:text-slate-300 underline">Fechar</button>
               </div>
             )}

             {currentRanking.length > 0 ? (
               <div className="space-y-10">
                 <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
                    <div className="lg:col-span-3 bg-slate-900/50 p-6 rounded-2xl border border-slate-800 h-[350px]">
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={chartData}>
                          <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                          <XAxis dataKey="nick" stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                          <YAxis stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                          <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '12px' }} />
                          <Bar dataKey="kd" radius={[6, 6, 0, 0]} barSize={40}>
                             {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.kd >= 1.5 ? '#10b981' : entry.kd >= 1.0 ? '#3b82f6' : '#f43f5e'} />)}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                   </div>
                   <div className="bg-slate-900 border border-slate-800 p-8 rounded-2xl flex flex-col justify-center items-center text-center shadow-xl">
                      <div className="mb-6">
                        <p className="text-slate-500 uppercase text-xs font-bold mb-1">Kills</p>
                        <p className="text-5xl font-gaming font-bold text-emerald-400">
                          {currentRanking.reduce((acc, curr) => acc + curr.kills, 0)}
                        </p>
                      </div>
                      <div className="w-full h-px bg-slate-800 my-4"></div>
                      <div>
                        <p className="text-slate-500 uppercase text-xs font-bold mb-1">Dano Total</p>
                        <p className="text-3xl font-gaming font-bold text-orange-400">
                          {(currentRanking.reduce((acc, curr) => acc + curr.damage, 0)).toLocaleString('pt-BR')}
                        </p>
                      </div>
                   </div>
                 </div>
                 <RankingTable data={currentRanking} />
               </div>
             ) : (
               <div className="text-center py-32 bg-slate-900/30 border border-slate-800 rounded-3xl border-dashed">
                 <p className="text-slate-500 text-lg italic">
                    {players.length === 0 ? 'Conectando ao banco de dados...' : 'Sem dados para esta temporada.'}
                 </p>
               </div>
             )}
          </div>
        ) : view === 'balancer' ? (
          <TeamBalancer players={players} seasons={seasons} stats={stats} />
        ) : !userRole ? (
          <div className="max-w-md mx-auto mt-20 p-10 bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl animate-in zoom-in-95">
            <h2 className="text-2xl font-gaming font-bold text-center mb-6 text-emerald-400">Acesso Restrito</h2>
            <form onSubmit={handleLogin} className="space-y-4">
              <input 
                type="password" 
                value={adminPasswordInput} 
                onChange={(e) => {setAdminPasswordInput(e.target.value); setLoginError(false);}} 
                placeholder="Senha de Acesso" 
                className={`w-full bg-slate-800 border ${loginError ? 'border-rose-500' : 'border-slate-700'} rounded-xl px-4 py-4 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-emerald-500 transition-all`}
                autoFocus 
              />
              <div className="text-xs text-slate-500 text-center">
                 <p className="mb-1">Admin Master (Root) ou Editor (x5admin2024)</p>
              </div>
              <button type="submit" className="w-full bg-emerald-600 hover:bg-emerald-700 py-4 rounded-xl font-bold shadow-lg transition-all">Entrar no Painel</button>
            </form>
          </div>
        ) : (
          <AdminPanel 
            role={userRole}
            players={players} seasons={seasons} stats={stats}
            onAddPlayer={handleAddPlayer} onDeletePlayer={handleDeletePlayer}
            onAddSeason={handleAddSeason} onDeleteSeason={handleDeleteSeason}
            onUpdateStats={handleUpdateStats} 
            onOverwriteStats={handleOverwriteStats}
            onEditPlayer={handleEditPlayer}
            onResetData={handleResetData} onSetView={setView}
            onEditSeason={() => {}}
            onPublish={handlePublishToCloud}
          />
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full bg-slate-900/80 backdrop-blur-md border-t border-slate-800/50 py-3 text-center z-40">
        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
          X5 Friends Ranking &bull; Dados em Nuvem
        </p>
      </footer>
    </div>
  );
};

export default App;

export interface Player {
  id: string;
  nick: string;
}

export interface Season {
  id: string;
  name: string;
}

export interface PlayerStats {
  id: string;
  playerId: string;
  seasonId: string;
  matches: number;
  kills: number;
  deaths: number;
  assists: number;
  damage: number;
}

export interface FullRankingEntry extends PlayerStats {
  nick: string;
  kd: number;
  damagePerMatch: number;
  trend?: number; // Diferença de posição: >0 (Subiu), <0 (Desceu), 0 (Igual), undefined (Novo)
}

export type ViewType = 'ranking' | 'admin' | 'balancer';

export type UserRole = 'master' | 'editor' | null;

import React, { useState, useEffect, useMemo } from 'react';
import { ViewType, Player, Season, PlayerStats, FullRankingEntry, UserRole } from './types';
import RankingTable from './components/RankingTable';
import AdminPanel from './components/AdminPanel';
import TeamBalancer from './components/TeamBalancer';
import { db } from './services/databaseService';
import { getRankingInsights } from './services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

// Configuração de Senhas e Níveis
const AUTH_CONFIG = {
  MASTER_PASSWORD: "x5root2025",  // NOVA Senha Master (Permissão Total + Configs)
  EDITOR_PASSWORD: "x5admin2024"  // ANTIGA Senha Master -> Agora Editor (Apenas Stats/Add Player)
};

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('ranking');

  // Estado de Autenticação com Role
  const [userRole, setUserRole] = useState<UserRole>(() => {
    return (sessionStorage.getItem('x5_user_role') as UserRole) || null;
  });

  const [players, setPlayers] = useState<Player[]>([]);
  const [seasons, setSeasons] = useState<Season[]>([]);
  const [stats, setStats] = useState<PlayerStats[]>([]);

  const [isLoading, setIsLoading] = useState(true);
  const [selectedSeasonId, setSelectedSeasonId] = useState('');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loadingAi, setLoadingAi] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [loginError, setLoginError] = useState(false);

  // Estado para armazenar o snapshot anterior do ranking (para comparar subidas/descidas)
  const [rankingSnapshot, setRankingSnapshot] = useState<FullRankingEntry[]>([]);

  // Busca dados automaticamente ao carregar
  const fetchData = async () => {
    setIsLoading(true);

    try {
      const [cloudPlayers, cloudSeasons, cloudStats] = await Promise.all([
        db.getPlayers(),
        db.getSeasons(),
        db.getStats()
      ]);

      if (cloudPlayers && cloudSeasons && cloudStats) {
        setPlayers(cloudPlayers || []);
        setSeasons(cloudSeasons || []);
        setStats(cloudStats || []);

        // Seleciona automaticamente a última temporada alimentada
        if (cloudSeasons && cloudSeasons.length > 0 && !selectedSeasonId) {
          setSelectedSeasonId(cloudSeasons[0].id);
        }
      }
    } catch (error) {
      console.error("Erro ao buscar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // Carrega o snapshot do LocalStorage quando a temporada muda
  useEffect(() => {
    if (selectedSeasonId) {
      const savedSnapshot = localStorage.getItem(`x5_rank_snap_${selectedSeasonId}`);
      if (savedSnapshot) {
        try {
          setRankingSnapshot(JSON.parse(savedSnapshot));
        } catch (e) {
          setRankingSnapshot([]);
        }
      } else {
        setRankingSnapshot([]);
      }
    }
  }, [selectedSeasonId]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();

    if (adminPasswordInput === AUTH_CONFIG.MASTER_PASSWORD) {
      setUserRole('master');
      sessionStorage.setItem('x5_user_role', 'master');
      setLoginError(false);
      setAdminPasswordInput('');
    } else if (adminPasswordInput === AUTH_CONFIG.EDITOR_PASSWORD) {
      setUserRole('editor');
      sessionStorage.setItem('x5_user_role', 'editor');
      setLoginError(false);
      setAdminPasswordInput('');
    } else {
      setLoginError(true);
      setUserRole(null);
    }
  };

  const handleLogout = () => {
    setUserRole(null);
    sessionStorage.removeItem('x5_user_role');
    setView('ranking');
  };

  const handleResetData = async () => {
    if (window.confirm("ATENÇÃO: Isso apagará TODOS os dados do banco de dados na nuvem. Continuar?")) {
      setIsLoading(true);
      await db.clearDatabase();
      window.location.reload();
    }
  };

  // Calcula Ranking Atual + Tendência (Trend)
  const currentRanking: FullRankingEntry[] = useMemo(() => {
    if (!selectedSeasonId) return [];

    // 1. Calcula Ranking Base
    const rawRanking = stats
      .filter(s => s.seasonId === selectedSeasonId)
      .map(s => {
        const player = players.find(p => p.id === s.playerId);
        const kdValue = s.deaths === 0 ? s.kills : s.kills / s.deaths;
        return {
          ...s,
          nick: player?.nick || 'Desconhecido',
          kd: kdValue,
          damagePerMatch: s.matches === 0 ? 0 : s.damage / s.matches
        };
      })
      .sort((a, b) => {
        // Ordenação primária KD
        if (b.kd !== a.kd) return b.kd - a.kd;
        // Desempate por Kills
        return b.kills - a.kills;
      });

    // 2. Calcula Tendências comparando com rankingSnapshot
    // Só calculamos tendência para jogadores com 3+ partidas (os que aparecem no ranking oficial)
    const activePlayers = rawRanking.filter(p => p.matches >= 3);

    // Mapa de posições antigas
    const prevPositions = new Map<string, number>();
    if (rankingSnapshot.length > 0) {
       // O snapshot já deve estar ordenado e filtrado
       rankingSnapshot.forEach((p, index) => {
         prevPositions.set(p.playerId, index);
       });
    }

    // Injeta a tendência nos dados atuais
    return rawRanking.map((player) => {
      // Se o jogador não tem partidas suficientes, não tem rank, logo não tem trend visual
      if (player.matches < 3) return { ...player, trend: 0 };

      const currentIndex = activePlayers.findIndex(p => p.playerId === player.playerId);
      const prevIndex = prevPositions.get(player.playerId);

      let trend = 0;
      if (prevIndex !== undefined && currentIndex !== -1) {
        // Ex: Estava em 5º (4), agora em 2º (1). Trend = 4 - 1 = 3 (Subiu 3)
        trend = prevIndex - currentIndex;
      } else if (prevIndex === undefined && currentIndex !== -1 && rankingSnapshot.length > 0) {
        // Entrou no ranking agora (novo)
        trend = 999; 
      }

      return { ...player, trend };
    });

  }, [stats, selectedSeasonId, players, rankingSnapshot]);

  // Salva o novo estado no LocalStorage (mas não atualiza rankingSnapshot para não perder a referência visual da sessão)
  useEffect(() => {
    if (currentRanking.length > 0 && selectedSeasonId) {
      const activeOnly = currentRanking.filter(p => p.matches >= 3);
      // Pequeno delay para garantir que não estamos salvando lixo ou estados intermediários
      const timer = setTimeout(() => {
         localStorage.setItem(`x5_rank_snap_${selectedSeasonId}`, JSON.stringify(activeOnly));
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [currentRanking, selectedSeasonId]);

  // Filtra dados para o gráfico (apenas jogadores com 3+ partidas)
  const chartData = useMemo(() => {
    return currentRanking.filter(p => p.matches >= 3);
  }, [currentRanking]);

  // Admin Actions Handlers
  const handleAddPlayer = (nick: string) => setPlayers(prev => [...prev, { id: `p${Date.now()}`, nick }]);

  const handleEditPlayer = (id: string, newNick: string) => {
    setPlayers(prev => prev.map(p => p.id === id ? { ...p, nick: newNick } : p));
  };

  const handleDeletePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
    setStats(prev => prev.filter(s => s.playerId !== id));
  };

  const handleAddSeason = (name: string) => {
    const id = `s${Date.now()}`;
    setSeasons(prev => [{ id, name }, ...prev]); 
    if (!selectedSeasonId) setSelectedSeasonId(id);
  };

  const handleDeleteSeason = (id: string) => {
    setSeasons(prev => prev.filter(s => s.id !== id));
    setStats(prev => prev.filter(s => s.seasonId !== id));
    if(selectedSeasonId === id && seasons.length > 1) setSelectedSeasonId(seasons[1].id);
    else if(selectedSeasonId === id) setSelectedSeasonId('');
  };

  const handleUpdateStats = (entry: Omit<PlayerStats, 'id'>) => {
    setStats(prev => {
      const newStats = [...prev];
      const idx = newStats.findIndex(s => s.playerId === entry.playerId && s.seasonId === entry.seasonId);
      if (idx > -1) {
        newStats[idx] = { 
          ...newStats[idx], 
          matches: newStats[idx].matches + entry.matches,
          kills: newStats[idx].kills + entry.kills,
          deaths: newStats[idx].deaths + entry.deaths,
          assists: newStats[idx].assists + entry.assists,
          damage: newStats[idx].damage + entry.damage
        };
      } else {
        newStats.push({ ...entry, id: `st${Date.now()}` });
      }
      return newStats;
    });
  };

  const handleOverwriteStats = (entry: Omit<PlayerStats, 'id'>) => {
    setStats(prev => {
      const newStats = [...prev];
      const idx = newStats.findIndex(s => s.playerId === entry.playerId && s.seasonId === entry.seasonId);
      if (idx > -1) {
        newStats[idx] = { 
          ...newStats[idx], 
          matches: entry.matches,
          kills: entry.kills,
          deaths: entry.deaths,
          assists: entry.assists,
          damage: entry.damage
        };
      } else {
        newStats.push({ ...entry, id: `st${Date.now()}` });
      }
      return newStats;
    });
  };

  const handlePublishToCloud = async () => {
    setIsLoading(true);
    try {
      await db.syncDatabase(players, seasons, stats);
      alert("✅ Dados sincronizados com sucesso!");
    } catch (e: any) {
      console.error(e);
      alert(`❌ Falha ao publicar: ${e.message || "Erro desconhecido"}`);
    } finally {
      setIsLoading(false);
    }
  };

  const generateAICommentary = async () => {
    if (currentRanking.length === 0) return;
    setLoadingAi(true);
    const seasonName = seasons.find(s => s.id === selectedSeasonId)?.name || 'Temporada';
    const insight = await getRankingInsights(currentRanking, seasonName);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  if (isLoading && view === 'ranking' && players.length === 0) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center text-slate-400 font-gaming">
        <div className="w-12 h-12 border-2 border-purple-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-sm tracking-widest uppercase opacity-50">Carregando X5 Ranking...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 bg-slate-900/90 backdrop-blur-md border-b border-slate-800 px-6 py-4 shadow-xl">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => { setView('ranking'); fetchData(); }}>
            <div className="w-10 h-10 bg-emerald-600 rounded-lg flex items-center justify-center font-gaming text-2xl font-bold italic shadow-lg shadow-purple-500/20">X5</div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-gaming font-bold tracking-tight bg-gradient-to-r from-purple-400 to-blue-400 bg-clip-text text-transparent">
                RANKING AMIGOS
              </h1>
              <span className="text-[9px] font-bold text-slate-500 uppercase tracking-tighter">
                Estatísticas em Tempo Real
              </span>
            </div>
          </div>

          <nav className="flex items-center gap-2 bg-slate-800 p-1 rounded-xl border border-slate-700 overflow-x-auto">
            <button onClick={() => setView('ranking')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm whitespace-nowrap ${view === 'ranking' ? 'bg-purple-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Ranking</button>
            <button onClick={() => setView('balancer')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm whitespace-nowrap ${view === 'balancer' ? 'bg-purple-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Sorteio Teams</button>
            <button onClick={() => setView('admin')} className={`px-4 sm:px-6 py-2 rounded-lg font-bold transition-all text-xs sm:text-sm whitespace-nowrap ${view === 'admin' ? 'bg-purple-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>Admin</button>
            {userRole && (
               <button onClick={handleLogout} className="px-3 py-2 text-rose-400 hover:text-rose-300 hover:bg-rose-950/30 rounded-lg font-bold text-xs" title="Sair do modo Admin">
                 SAIR
               </button>
            )}
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {view === 'ranking' ? (
          <div className="space-y-8 animate-in fade-in duration-500">
             <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="w-full md:w-auto">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Selecione a Temporada</label>
                  <select 
                    value={selectedSeasonId} 
                    onChange={(e) => setSelectedSeasonId(e.target.value)} 
                    className="w-full md:w-72 bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-purple-500 shadow-xl"
                  >
                    {seasons.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    {seasons.length === 0 && <option value="">Nenhuma temporada encontrada</option>}
                  </select>
                </div>
                <button onClick={generateAICommentary} disabled={loadingAi || currentRanking.length === 0} className="w-full md:w-auto flex items-center justify-center gap-2 bg-gradient-to-r from-purple-600 to-blue-600 px-8 py-4 rounded-xl font-bold shadow-2xl transition-all disabled:opacity-50">
                  {loadingAi ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : "✨ Analisar com Gemini"}
                </button>
             </div>

             {aiInsight && (
               <div className="bg-slate-900 border border-emerald-500/20 p-6 rounded-2xl shadow-2xl animate-in slide-in-from-top-4">
                 <h3 className="text-emerald-400 font-bold mb-2">✨ Insight da IA</h3>
                 <div className="text-slate-300 italic whitespace-pre-wrap">{aiInsight}</div>
                 <button onClick={() => setAiInsight('')} className="mt-4 text-[10px] text-slate-500 uppercase hover:text-slate-300 underline">Fechar</button>
               </div>
             )}

             {currentRanking.length > 0 ? (
               <div className="space-y-10">
                 <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
                    <div className="lg:col-span-3 bg-slate-900/50 p-6 rounded-2xl border border-slate-800 h-[350px]">
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={chartData}>
                          <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                          <XAxis dataKey="nick" stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                          <YAxis stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                          <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '12px' }} />
                          <Bar dataKey="kd" radius={[6, 6, 0, 0]} barSize={40}>
                             {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.kd >= 1.5 ? '#10b981' : entry.kd >= 1.0 ? '#3b82f6' : '#f43f5e'} />)}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                   </div>
                   <div className="bg-slate-900 border border-slate-800 p-8 rounded-2xl flex flex-col justify-center items-center text-center shadow-xl">
                      <div className="mb-6">
                        <p className="text-slate-500 uppercase text-xs font-bold mb-1">Kills</p>
                        <p className="text-5xl font-gaming font-bold text-emerald-400">
                          {currentRanking.reduce((acc, curr) => acc + curr.kills, 0)}
                        </p>
                      </div>
                      <div className="w-full h-px bg-slate-800 my-4"></div>
                      <div>
                        <p className="text-slate-500 uppercase text-xs font-bold mb-1">Dano Total</p>
                        <p className="text-3xl font-gaming font-bold text-orange-400">
                          {(currentRanking.reduce((acc, curr) => acc + curr.damage, 0)).toLocaleString('pt-BR')}
                        </p>
                      </div>
                   </div>
                 </div>
                 <RankingTable data={currentRanking} />
               </div>
             ) : (
               <div className="text-center py-32 bg-slate-900/30 border border-slate-800 rounded-3xl border-dashed">
                 <p className="text-slate-500 text-lg italic">
                    {players.length === 0 ? 'Conectando ao banco de dados...' : 'Sem dados para esta temporada.'}
                 </p>
               </div>
             )}
          </div>
        ) : view === 'balancer' ? (
          <TeamBalancer players={players} seasons={seasons} stats={stats} />
        ) : !userRole ? (
          <div className="max-w-md mx-auto mt-20 p-10 bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl animate-in zoom-in-95">
            <h2 className="text-2xl font-gaming font-bold text-center mb-6 text-emerald-400">Acesso Restrito</h2>
            <form onSubmit={handleLogin} className="space-y-4">
              <input 
                type="password" 
                value={adminPasswordInput} 
                onChange={(e) => {setAdminPasswordInput(e.target.value); setLoginError(false);}} 
                placeholder="Senha de Acesso" 
                className={`w-full bg-slate-800 border ${loginError ? 'border-rose-500' : 'border-slate-700'} rounded-xl px-4 py-4 font-bold text-slate-200 outline-none focus:ring-2 focus:ring-emerald-500 transition-all`}
                autoFocus 
              />
              <div className="text-xs text-slate-500 text-center">
                 <p className="mb-1">Admin Master (Root) ou Editor (x5admin2024)</p>
              </div>
              <button type="submit" className="w-full bg-emerald-600 hover:bg-emerald-700 py-4 rounded-xl font-bold shadow-lg transition-all">Entrar no Painel</button>
            </form>
          </div>
        ) : (
          <AdminPanel 
            role={userRole}
            players={players} seasons={seasons} stats={stats}
            onAddPlayer={handleAddPlayer} onDeletePlayer={handleDeletePlayer}
            onAddSeason={handleAddSeason} onDeleteSeason={handleDeleteSeason}
            onUpdateStats={handleUpdateStats} 
            onOverwriteStats={handleOverwriteStats}
            onEditPlayer={handleEditPlayer}
            onResetData={handleResetData} onSetView={setView}
            onEditSeason={() => {}}
            onPublish={handlePublishToCloud}
          />
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full bg-slate-900/80 backdrop-blur-md border-t border-slate-800/50 py-3 text-center z-40">
        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
          X5 Friends Ranking &bull; Dados em Nuvem
        </p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { FullRankingEntry } from '../types';

interface RankingTableProps {
  data: FullRankingEntry[];
}

type SortKey = keyof FullRankingEntry;
type SortDirection = 'asc' | 'desc';

interface SortConfig {
  key: SortKey;
  direction: SortDirection;
}

const RankingTable: React.FC<RankingTableProps> = ({ data }) => {
  // Estado padrão: Ordenado por KD descendente (maior para o menor)
  const [sortConfig, setSortConfig] = useState<SortConfig>({
    key: 'kd',
    direction: 'desc',
  });

  const handleSort = (key: SortKey) => {
    setSortConfig((current) => ({
      key,
      direction: current.key === key && current.direction === 'desc' ? 'asc' : 'desc',
    }));
  };

  const sortedData = useMemo(() => {
    // Filtra jogadores com menos de 3 partidas antes de ordenar
    const filtered = data.filter(player => player.matches >= 3);
    const sorted = [...filtered];

    return sorted.sort((a, b) => {
      // @ts-ignore
      const aValue = a[sortConfig.key];
      // @ts-ignore
      const bValue = b[sortConfig.key];

      if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
  }, [data, sortConfig]);

  const SortIcon = ({ columnKey }: { columnKey: SortKey }) => {
    const isActive = sortConfig.key === columnKey;

    return (
      <span className={`ml-2 inline-flex flex-col h-3 w-3 justify-center items-center transition-opacity ${isActive ? 'opacity-100' : 'opacity-20 group-hover:opacity-50'}`}>
        {/* Seta para cima */}
        <svg 
          className={`w-2 h-2 -mb-[2px] ${isActive && sortConfig.direction === 'asc' ? 'text-emerald-400' : 'text-slate-400'}`} 
          fill="currentColor" viewBox="0 0 24 24"
        >
          <path d="M12 4l-8 8h16l-8-8z" />
        </svg>
        {/* Seta para baixo */}
        <svg 
          className={`w-2 h-2 -mt-[2px] ${isActive && sortConfig.direction === 'desc' ? 'text-emerald-400' : 'text-slate-400'}`} 
          fill="currentColor" viewBox="0 0 24 24"
        >
          <path d="M12 20l8-8H4l8 8z" />
        </svg>
      </span>
    );
  };

  const renderHeader = (label: string, key: SortKey, colorClass: string = "text-slate-300", align: string = "text-left", title?: string) => (
    <th 
      className={`px-6 py-4 cursor-pointer group select-none transition-colors hover:bg-slate-800/50 ${colorClass} ${align}`}
      onClick={() => handleSort(key)}
      title={title}
    >
      <div className={`flex items-center ${align === "text-center" ? "justify-center" : "justify-start"}`}>
        {label}
        <SortIcon columnKey={key} />
      </div>
    </th>
  );

  return (
    <div className="overflow-x-auto rounded-xl border border-slate-700 bg-slate-800/50 backdrop-blur-sm shadow-2xl">
      <table className="w-full text-left border-collapse">
        <thead className="bg-slate-900/80 font-gaming uppercase tracking-wider text-sm">
          <tr>
            <th className="px-6 py-4 text-slate-500 w-20">#</th>
            {renderHeader("Nick", "nick", "text-slate-300")}
            {renderHeader("Partidas", "matches", "text-slate-300")}
            {renderHeader("Vítimas", "kills", "text-emerald-400")}
            {renderHeader("Mortes", "deaths", "text-rose-400")}
            {renderHeader("Assists", "assists", "text-sky-400")}
            {renderHeader("Dano", "damage", "text-orange-400")}
            {renderHeader("K/D", "kd", "text-yellow-400", "text-left", "Cálculo: Vítimas / Mortes")}
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-700">
          {sortedData.length === 0 ? (
            <tr>
              <td colSpan={8} className="px-6 py-10 text-center text-slate-500 italic">
                {data.length > 0 
                  ? "Nenhum jogador elegível (mínimo 3 partidas)."
                  : "Nenhum dado encontrado para esta temporada."}
              </td>
            </tr>
          ) : (
            sortedData.map((player, index) => (
              <tr 
                key={player.id} 
                className="hover:bg-slate-700/50 transition-colors group cursor-default"
              >
                <td className="px-6 py-4 font-gaming text-lg">
                  <div className="flex items-center gap-2">
                    <span className={`
                      w-8 h-8 flex items-center justify-center rounded-full text-sm
                      ${index === 0 && sortConfig.key === 'kd' && sortConfig.direction === 'desc' ? 'bg-yellow-500/20 text-yellow-400 ring-1 ring-yellow-500' : ''}
                      ${index === 1 && sortConfig.key === 'kd' && sortConfig.direction === 'desc' ? 'bg-slate-400/20 text-slate-300 ring-1 ring-slate-400' : ''}
                      ${index === 2 && sortConfig.key === 'kd' && sortConfig.direction === 'desc' ? 'bg-orange-700/20 text-orange-400 ring-1 ring-orange-700' : ''}
                      ${(index > 2 || sortConfig.key !== 'kd' || sortConfig.direction !== 'desc') ? 'text-slate-500' : ''}
                    `}>
                      {index + 1}
                    </span>

                    {/* INDICADOR DE TENDÊNCIA (TREND) */}
                    <div className="w-5 flex justify-center">
                        {player.trend && player.trend > 0 ? (
                            <span className="text-emerald-500 text-[10px] font-bold flex flex-col items-center animate-in slide-in-from-bottom-2">
                                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 15l7-7 7 7"></path></svg>
                                <span className="-mt-1">{player.trend}</span>
                            </span>
                        ) : player.trend && player.trend < 0 ? (
                            <span className="text-rose-500 text-[10px] font-bold flex flex-col items-center animate-in slide-in-from-top-2">
                                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"></path></svg>
                                <span className="-mt-1">{Math.abs(player.trend)}</span>
                            </span>
                        ) : player.trend === 999 ? (
                            <span className="text-[9px] bg-emerald-900 text-emerald-300 px-1 rounded animate-pulse">NEW</span>
                        ) : (
                            <span className="text-slate-600 text-lg leading-none">-</span>
                        )}
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4 font-bold text-slate-100 group-hover:text-blue-400 transition-colors">
                  {player.nick}
                </td>
                <td className="px-6 py-4 text-slate-300">{player.matches}</td>
                <td className="px-6 py-4 text-emerald-400 font-medium">{player.kills}</td>
                <td className="px-6 py-4 text-rose-400 font-medium">{player.deaths}</td>
                <td className="px-6 py-4 text-sky-400">{player.assists}</td>
                <td className="px-6 py-4 text-orange-400 font-medium">
                  {player.damage.toLocaleString('pt-BR')}
                </td>
                <td className="px-6 py-4">
                  <span className={`
                    px-2 py-1 rounded font-bold
                    ${player.kd >= 1.5 ? 'bg-emerald-500/20 text-emerald-400' : 
                      player.kd >= 1.0 ? 'bg-blue-500/20 text-blue-400' : 
                      'bg-rose-500/20 text-rose-400'}
                  `}>
                    {player.kd.toFixed(2)}
                  </span>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
};

export default RankingTable;

import React, { useState, useMemo } from 'react';
import { FullRankingEntry } from '../types';

interface RankingTableProps {
  data: FullRankingEntry[];
}

type SortKey = keyof FullRankingEntry;
type SortDirection = 'asc' | 'desc';

interface SortConfig {
  key: SortKey;
  direction: SortDirection;
}

const RankingTable: React.FC<RankingTableProps> = ({ data }) => {
  // Estado padrão: Ordenado por KD descendente (maior para o menor)
  const [sortConfig, setSortConfig] = useState<SortConfig>({
    key: 'kd',
    direction: 'desc',
  });

  const handleSort = (key: SortKey) => {
    setSortConfig((current) => ({
      key,
      direction: current.key === key && current.direction === 'desc' ? 'asc' : 'desc',
    }));
  };

  const sortedData = useMemo(() => {
    // Filtra jogadores com menos de 3 partidas antes de ordenar
    const filtered = data.filter(player => player.matches >= 3);
    const sorted = [...filtered];

    return sorted.sort((a, b) => {
      // @ts-ignore
      const aValue = a[sortConfig.key];
      // @ts-ignore
      const bValue = b[sortConfig.key];

      if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
  }, [data, sortConfig]);

  const SortIcon = ({ columnKey }: { columnKey: SortKey }) => {
    const isActive = sortConfig.key === columnKey;

    return (
      <span className={`ml-2 inline-flex flex-col h-3 w-3 justify-center items-center transition-opacity ${isActive ? 'opacity-100' : 'opacity-20 group-hover:opacity-50'}`}>
        {/* Seta para cima */}
        <svg 
          className={`w-2 h-2 -mb-[2px] ${isActive && sortConfig.direction === 'asc' ? 'text-emerald-400' : 'text-slate-400'}`} 
          fill="currentColor" viewBox="0 0 24 24"
        >
          <path d="M12 4l-8 8h16l-8-8z" />
        </svg>
        {/* Seta para baixo */}
        <svg 
          className={`w-2 h-2 -mt-[2px] ${isActive && sortConfig.direction === 'desc' ? 'text-emerald-400' : 'text-slate-400'}`} 
          fill="currentColor" viewBox="0 0 24 24"
        >
          <path d="M12 20l8-8H4l8 8z" />
        </svg>
      </span>
    );
  };

  const renderHeader = (label: string, key: SortKey, colorClass: string = "text-slate-300", align: string = "text-left", title?: string) => (
    <th 
      className={`px-4 py-4 cursor-pointer group select-none transition-colors hover:bg-slate-800/50 ${colorClass} ${align}`}
      onClick={() => handleSort(key)}
      title={title}
    >
      <div className={`flex items-center ${align === "text-center" ? "justify-center" : "justify-start"}`}>
        {label}
        <SortIcon columnKey={key} />
      </div>
    </th>
  );

  return (
    <div className="overflow-x-auto rounded-xl border border-slate-700 bg-slate-800/50 backdrop-blur-sm shadow-2xl">
      <table className="w-full text-left border-collapse">
        <thead className="bg-slate-900/80 font-gaming uppercase tracking-wider text-sm">
          <tr>
            <th className="px-6 py-4 text-slate-500 w-24 text-center">RANK</th>
            {renderHeader("Nick", "nick", "text-slate-300")}
            {renderHeader("Matches", "matches", "text-slate-300")}
            {renderHeader("Kills", "kills", "text-emerald-400")}
            {renderHeader("Deaths", "deaths", "text-rose-400")}
            {renderHeader("Assists", "assists", "text-sky-400")}
            {renderHeader("Dano", "damage", "text-orange-400")}
            {renderHeader("K/D", "kd", "text-yellow-400", "text-left", "Cálculo: Vítimas / Mortes")}
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-700">
          {sortedData.length === 0 ? (
            <tr>
              <td colSpan={8} className="px-6 py-10 text-center text-slate-500 italic">
                {data.length > 0 
                  ? "Nenhum jogador elegível (mínimo 3 partidas)."
                  : "Nenhum dado encontrado para esta temporada."}
              </td>
            </tr>
          ) : (
            sortedData.map((player, index) => (
              <tr 
                key={player.id} 
                className="hover:bg-slate-700/50 transition-colors group cursor-default"
              >
                <td className="px-4 py-4 font-gaming text-lg">
                  <div className="flex flex-col items-center justify-center w-full">
                    <span className={`
                      w-8 h-8 flex items-center justify-center rounded-full text-lg font-bold mb-1
                      ${index === 0 && sortConfig.key === 'kd' && sortConfig.direction === 'desc' ? 'bg-yellow-500 text-slate-900 shadow-lg shadow-yellow-500/50' : ''}
                      ${index === 1 && sortConfig.key === 'kd' && sortConfig.direction === 'desc' ? 'bg-slate-300 text-slate-900 shadow-lg shadow-slate-300/50' : ''}
                      ${index === 2 && sortConfig.key === 'kd' && sortConfig.direction === 'desc' ? 'bg-orange-600 text-slate-100 shadow-lg shadow-orange-600/50' : ''}
                      ${(index > 2 || sortConfig.key !== 'kd' || sortConfig.direction !== 'desc') ? 'text-slate-400 bg-slate-800 border border-slate-700' : ''}
                    `}>
                      {index + 1}
                    </span>

                    {/* INDICADOR DE TENDÊNCIA (TREND) */}
                    <div className="h-4 flex items-center justify-center w-full">
                        {player.trend !== undefined && player.trend > 0 ? (
                            <div className="flex items-center gap-0.5 text-emerald-500 animate-pulse bg-emerald-500/10 px-1.5 py-0.5 rounded text-[10px] font-bold border border-emerald-500/20">
                                <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 15l7-7 7 7"></path></svg>
                                {player.trend}
                            </div>
                        ) : player.trend !== undefined && player.trend < 0 ? (
                            <div className="flex items-center gap-0.5 text-rose-500 bg-rose-500/10 px-1.5 py-0.5 rounded text-[10px] font-bold border border-rose-500/20">
                                <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"></path></svg>
                                {Math.abs(player.trend)}
                            </div>
                        ) : player.trend === 999 ? (
                            <span className="text-[9px] bg-blue-600 text-white px-1.5 py-0.5 rounded font-bold uppercase tracking-wider shadow-lg shadow-blue-500/20">NEW</span>
                        ) : (
                            <span className="text-slate-700 text-lg leading-none select-none">•</span>
                        )}
                    </div>
                  </div>
                </td>
                <td className="px-4 py-4 font-bold text-slate-100 group-hover:text-blue-400 transition-colors text-lg">
                  {player.nick}
                </td>
                <td className="px-4 py-4 text-slate-300 font-mono">{player.matches}</td>
                <td className="px-4 py-4 text-emerald-400 font-bold font-mono text-lg">{player.kills}</td>
                <td className="px-4 py-4 text-rose-400 font-bold font-mono text-lg">{player.deaths}</td>
                <td className="px-4 py-4 text-sky-400 font-mono">{player.assists}</td>
                <td className="px-4 py-4 text-orange-400 font-bold font-mono">
                  {player.damage.toLocaleString('pt-BR')}
                </td>
                <td className="px-4 py-4">
                  <span className={`
                    px-3 py-1.5 rounded-lg font-bold text-lg font-mono tracking-tight
                    ${player.kd >= 1.5 ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' : 
                      player.kd >= 1.0 ? 'bg-blue-500/20 text-blue-400 border border-blue-500/30' : 
                      'bg-rose-500/20 text-rose-400 border border-rose-500/30'}
                  `}>
                    {player.kd.toFixed(2)}
                  </span>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
};

export default RankingTable;
